import Contexts from '../Contexts';

class AlarmGUI {
    constructor(addViewOptions, time, ampm, context) {
        this._context = context;
        this._addViewOptions = addViewOptions;
        this._alarmTimerMovieClip = null;

        this.time = time;
        this.ampm = ampm;
    }

    changeTime(time, ampm) {
        this.time = time;
        this.ampm = ampm;
    }

    displayNewSetTime() {
        return new Promise((resolve, reject) => {
            // If the current view is the alarm, don't add a new view.
            if (jibo.face.views.currentView && jibo.face.views.currentView.id === 'alarmView') {
                this.alarmGuiSetup();
                resolve();
            } else {
                if(this._context === Contexts.Menu) {
                    this._addViewOptions.remove = true;
                    this._addViewOptions.transitionClose = jibo.face.views.UP;
                    this._addViewOptions.transitionOpen = jibo.face.views.UP;
                }
                jibo.face.views.changeView(this._addViewOptions, resolve, reject, (view) => {
                    try {
                        this._alarmTimerMovieClip = view.getComponentById(`alarmClip`).movieClip;
                        this._alarmTimerMovieClip.gotoAndStop(`alarm_in_stop`);

                        view.addAction('event', {event: 'swipeDown'}, true, false, jibo.face.views.SWIPE);
                        view.addAction('mimEnd', null, false, false, jibo.face.views.SWIPE);
                        view.addAction('mimEnd', null, false, false, jibo.face.views.TAP);

                        this.alarmGuiSetup();
                    } catch(err) {
                        reject(err);
                    }
                });
            }
        });
    }

    alarmGuiSetup() {
        let timeClip = this._alarmTimerMovieClip.timeClip;
        timeClip.tapToEdit.alpha = 1;
        if (!this.time) {
            timeClip.time.alpha = 0;
            timeClip.am_pm.alpha = 0;
            timeClip.question.alpha = 1;
        } else {
            timeClip.question.alpha = 0;
            timeClip.time.alpha = 1;
            timeClip.am_pm.alpha = 1;

            timeClip.am_pm.text = this.ampm || 'AM? PM?';
            timeClip.time.text = this.time;
        }
    }

    cleanUpTimers() {
        return;
    }
}

export default AlarmGUI;
