"use strict";

export default class Utils {
    // find the (integer) frame number which corresponds to a label name
    // this throws an exception if it is unable to find the label name
    static findLabelFramePositionFromName(labels, labelName) {
        for(let i = 0; i < labels.length; ++i) {
            if(labels[i].label === labelName) {
                return labels[i].position;
            }
        }

        throw "could not find frame: " + labelName;
    }
}
