import SubSkill from './SubSkill';
import Contexts from './Contexts';
let ActionData = jibo.rendering.gui.actions.ActionData;
let Mim = jibo.bt.behaviors.Mim;

class MenuSubSkill extends SubSkill {
    constructor(clockSkill, assetPack, context=null, buttonPressCallback) {
        super();
        this.log = clockSkill.log.createChild('Menu');

        this._clockSkill = clockSkill;
        this._assetPack = assetPack;
        this._context = context;
        this._menuView = null;
        this._buttonPressCallback = buttonPressCallback;
        this._action = MenuSubSkill.actions.NONE;

        this._menuMim = null;
        this._updateMethod = this.update.bind(this);
        this._isRunning = false;
    }

    get name() {
        return "MenuSubSkill";
    }

    hasTimedOut(startTime) {
        if (this._menuMim) {
            const mimStatus = this._menuMim.update();
            return mimStatus !== jibo.bt.Status.IN_PROGRESS;
        } else {
            return Date.now() - startTime >= 8000;
        }
    }

    get movieClip() {
        return null;
    }

    run() {
        return new Promise((resolve, reject)=>{
            try {
                this._isRunning = true;
                let viewComplete = (/*menuView*/)=>{
                    resolve();
                };
                let onFailure = ()=>{
                    reject("clock menu change view failure");
                };
                let viewLoaded = (menuView) => {
                    try {
                        this._menuView = menuView;
                        this._menuView.swipeDownActions = [ new ActionData(ActionData.CALLBACK, {callback: ()=>{this._clockSkill.exit();}})];
                        jibo.timer.on('update', this._updateMethod);
                    } catch(err) {
                        reject(err);
                    }
                };

                let changeViewOptions = {
                    addView: "resources/views/menu.json",
                    transitionOpen: jibo.face.views.UP,
                    transitionClose: jibo.face.views.UP
                };
                if(this._context) {
                    changeViewOptions.remove = true;
                    changeViewOptions.transitionOpen = jibo.face.views.DOWN;
                }

                jibo.face.views.changeView(changeViewOptions, viewComplete, onFailure, viewLoaded);
            } catch(err) {
                reject(err);
            }
        });
    }

    update() {
        try {
            if(!this._menuMim) {
                this._menuMim = new Mim({
                    mimPath: "mims/Menu.mim",
                    assetPack: this._assetPack,
                    onSuccess: (result) => {
                        this.log.info('Menu MIM result:', result);
                        if (result && result.asrResults && result.state.lastResultState !== 'noInput') {
                            this._menuMimResult = result.asrResults;
                        }
                    }
                });
                this._menuMim.start();
            }
            let updateStatus = this._menuMim.update();
            if (updateStatus !== jibo.bt.Status.IN_PROGRESS) {
                jibo.timer.removeListener('update', this._updateMethod);
                // mim has been stopped at this point
                this._menuMim.destroy();
                this._menuMim = null;
                if (this._menuMimResult) {
                    this.onButtonPress(this._menuMimResult);
                }
            }
        } catch(err) {
            this.log.error(err);
        }
    }

    onButtonPress(event) {
        this.log.debug('button pressed. domain:', event.entities.domain, '| intent:', event.intent);
        this._action = MenuSubSkill.actions.BUTTON_CLICK;
        return this._clockSkill._model.loadRoot().then((rootNode) => {
            if ((event.entities.domain === this._clockSkill._timerDomain && rootNode.data.timer) ||
                (event.entities.domain === this._clockSkill._alarmDomain && rootNode.data.alarm)) {
                event.intent = 'query';
            }
        }).then(()=>{
            this._buttonPressCallback({ nlu: event, context: Contexts.Menu });
        });
    }

    animateOut(timedOut, movieClip, animationFinishedCallback) {
        animationFinishedCallback();
    }

    destroy(timedOut, callback) {
        Promise.resolve()
        .then(()=>{
            if (this._menuMim) {
                return this._menuMim.stop()
                .then(()=>{
                    this._menuMim.destroy();
                    this._menuMim = null;
                });
            }
        })
        .then(()=>{
            jibo.timer.removeListener('update', this._updateMethod);

            this._menuView = null;

            if(this._isRunning) {
                this._isRunning = false;

                // remove the top most level view
                if(this._action === MenuSubSkill.actions.NONE) {
                    return new Promise((resolve, reject) => {
                        let viewOptions = {
                            removeAll: true,
                            leaveEmpty: true,
                            transitionOpen: jibo.face.views.DOWN,
                            transitionClose: jibo.face.views.DOWN
                        };
                        let onFailure = (err) => {
                            reject(err);
                        }
                        jibo.face.views.changeView(viewOptions, resolve, onFailure);
                    });
                }
            }
        })
        .catch((err)=>{
            this.log.error(err);
        })
        .then(()=>{
            callback();
        });
    }
}

MenuSubSkill.actions = {
    NONE: 'NONE',
    BUTTON_CLICK: 'BUTTON_CLICK'
};

export default MenuSubSkill;
