import AlarmTimerUtils from './AlarmTimerUtils';

const jibo = require('jibo');
const View = jibo.rendering.gui.views.View;
const ActionData = jibo.rendering.gui.actions.ActionData;

export default class TimerEditGUIView extends View {
    constructor() {
        super();

        this._hours = 0;
        this._minutes = 0;
        this._editClip = null;
        this._setButton = null;
    }

    loadData(loadAssetsOnComplete) {
        // If there's data on the KB, populate the GUI with it
        jibo.kb.createModel('/jibo/clock/alarm_timer').loadRoot().then((rootNode) => {
            let data = rootNode.data;
            let timer = data.timer;
            if (timer) {
                let remainingMS = timer.endTime - Date.now();
                if (remainingMS > 0) {
                    this._hours = Math.floor( remainingMS / 1000 / 60 / 60 );
                    this._minutes = Math.floor( remainingMS / 1000 / 60 ) % 60;
                }
            }
            super.loadData(loadAssetsOnComplete);
        });
    }


    createDisplay(container, assets) {
        super.createDisplay(container, assets);
        this._editClip = this.getComponentById(`timerEdit`).movieClip;
        this.setupDisplay();
    }

    actionHandler(action, fromComponent) {
        if (action.type === ActionData.EVENT && action.data.event === 'confirmPress') {
            action = null;
            if (this._minutes || this._hours) {
                action = new ActionData(ActionData.UTTERANCE, {
                    utterance: {
                        intent: 'timerValue',
                        entities: {
                            domain: 'timer',
                            hours: this._hours,
                            minutes: this._minutes,
                            seconds: 'null'
                        }
                    }
                });
            }
        } else if (action.type === ActionData.EVENT && action.data.event === 'arrowPress') {
            let minutes = this._minutes + this._hours * 60 || 0;

            const timeIncrements = [ 60, 10, 1 ];

            if (action.data.arrow) {
                if (action.data.up) {
                    minutes += timeIncrements[action.data.digit];

                    if (minutes > 24 * 60) {
                        minutes = 24 * 60;
                    }
                } else {
                    if (minutes >= timeIncrements[action.data.digit]) {
                        minutes -= timeIncrements[action.data.digit];
                    }

                    if (minutes <= 0) {
                        minutes = 0;
                    }
                }
            }
            let hours = Math.floor(minutes / 60);
            minutes = minutes % 60;

            this.updateEditGui(hours, minutes);
            this._hours = hours;
            this._minutes = minutes;
            action = null;
        }
        if (action) {
            super.actionHandler(action, fromComponent);
        }
    }

    setupDisplay() {
        const HIT_AREA_WIDTH = 180;
        const BUTTON_SCALE = 0.5;
        const setButton = this._setButton = this.getComponentById('set_button');
        const cancelButton = this.getComponentById('cancel_button');
        const buttonOffset = (HIT_AREA_WIDTH - setButton.display.width) / 2;
        setButton.display.scale.x = setButton.display.scale.y = BUTTON_SCALE;
        cancelButton.display.scale.x = cancelButton.display.scale.y = BUTTON_SCALE;
        setButton.setupHitArea(new PIXI.Rectangle(buttonOffset, buttonOffset, HIT_AREA_WIDTH / BUTTON_SCALE, HIT_AREA_WIDTH / BUTTON_SCALE));
        cancelButton.setupHitArea(new PIXI.Rectangle(buttonOffset, buttonOffset, HIT_AREA_WIDTH / BUTTON_SCALE, HIT_AREA_WIDTH / BUTTON_SCALE));

        for (let i = 0; i < 3; ++i){
            this.getComponentById('arrow_up_0' + i).setupHitArea(new PIXI.Rectangle(-50, -37, 150, 150));
            let arrowDown = this.getComponentById('arrow_down_0' + i);
            arrowDown.setupHitArea(new PIXI.Rectangle(-50, -37, 150, 150));
            arrowDown.display.rotation = Math.PI;
        }
        this.updateEditGui(this._hours, this._minutes);
    }

    updateEditGui(hours, minutes) {
        hours = hours.toString();
        minutes = minutes < 10 ? AlarmTimerUtils.ZeroPad + minutes.toString() : minutes.toString();

        this._editClip.hourCounter.text = hours;
        this._editClip.minuteTensCounter.text = minutes.slice(0,1);
        this._editClip.minuteOnesCounter.text = minutes.slice(1);
    }
}
