import Contexts from './Contexts';
import SubSkill from './SubSkill';
import * as BeFramework from '@be/be-framework';
import Utils from './Utils';

let Mim = jibo.bt.behaviors.Mim;
let ActionData = jibo.rendering.gui.actions.ActionData;

const LOAD_DATE_VIEW_ERROR = "date changeview error";

class JiboDate extends SubSkill {

    constructor(clockSkill, assetPack, context=null) {
        super();

        JiboDate.LOAD_DATE_VIEW_ERROR = LOAD_DATE_VIEW_ERROR;
        this.log = clockSkill.log.createChild('Date');

        this._clockSkill = clockSkill;
        this._context = context;
        this._assetPack = assetPack;
        this._dateView = null;
        this._location = null;

        this._dateMim = null;
        this._updateMethod = this.update.bind(this);
        this._swipeDown = false;
    }

    get name() {
        return "JiboDate";
    }

    hasTimedOut(startTime) {
        if (this._dateMim) {
            const mimStatus = this._dateMim.update();
            // Timeout should last at least 3 seconds, but not cut off a longer mim
            return mimStatus !== jibo.bt.Status.IN_PROGRESS && Date.now() - startTime >= 3000;
        } else {
            return Date.now() - startTime >= 3000;
        }
    }

    get movieClip() {
        return this._dateMovieClip;
    }

    init(city, state, country, dayOfWeek, callback) {
        this._dayOfWeek = dayOfWeek;
        this._location = BeFramework.utils.Location.create(city, state, country);
        this._location.needsTimezone = true;
        this._location.fetch((err)=>{
            if(err) {
                this._location = BeFramework.utils.Location.jiboHome;
                this._location.needsTimezone = true;
                this._location.fetch((err)=>{
                    callback(err);
                });
            } else {
                let analyticsOtherTimezone = this._location.timezone.id !== BeFramework.utils.Location.jiboHome.timezone.id;
                this._clockSkill.analytics.currentDate(analyticsOtherTimezone);
                callback();
            }
        });
    }

    run() {
        return new Promise((resolve, reject)=>{
            try {
                let loadError = null;
                let onCompleteCallback = (/*dateView*/)=>{
                    if(loadError) {
                        reject(loadError);
                    } else {
                        resolve();
                    }
                };

                let onFailureCallback = (/*err*/)=>{
                    reject(LOAD_DATE_VIEW_ERROR);
                };

                let onLoadedCallback = (dateView)=>{
                    try {
                        this.createDateGuiComponents(dateView);
                        this.setContent(this._dateMovieClip);
                        let runUpdate = ()=>{
                            jibo.timer.on('update', this._updateMethod);
                        };

                        if(this._context === Contexts.Menu) {
                            // if we're coming from the menu, we want to animate to the date's menu_trans label before opening
                            PIXI.animate.Animator.play(this._dateMovieClip, "menu_trans", ()=>{
                                runUpdate();
                            });
                        } else {
                            // Start playing MIM immediately
                            runUpdate();
                            this.animateIn(this._dateMovieClip, ()=>{});
                        }
                    } catch(err) {
                        loadError = err;
                        this.log.error(loadError);
                    }
                };

                let changeViewOptions = {
                    addView: "resources/views/date.json",
                    transitionOpen: jibo.face.views.IN,
                    transitionClose: jibo.face.views.OUT
                };
                // if we've come from the menu, kill the menu view
                if(this._context === Contexts.Menu) {
                    changeViewOptions.remove = true;
                    changeViewOptions.transitionOpen = jibo.face.views.UP;
                    changeViewOptions.transitionClose = jibo.face.views.UP;
                }

                jibo.face.views.changeView(changeViewOptions, onCompleteCallback, onFailureCallback, onLoadedCallback);
            } catch(err) {
                reject(err);
            }
        });
    }

    createDateGuiComponents(dateView) {
        this._dateView = dateView;
        this._dateView.swipeDownActions = [ new ActionData(ActionData.CALLBACK, {callback: ()=>{
            this._swipeDown = true;
            if(this._context === Contexts.Menu) {
                this._clockSkill.refresh({ nlu: {entities:{domain: this._clockSkill._clockDomain}, intent: this._clockSkill._menuIntent}, context: Contexts.Date });
            } else {
                this._clockSkill.exit();
            }
        }})];
        this._dateMovieClip = this._dateView.getComponentById("dateClip").movieClip;
    }

    animateIn(dateMovieClip, callback) {
        this.log.debug('animate in');
        jibo.sound.play('sfxCalendarIn');

        // play the page flipping sound fx
        let pageFlipAnimationStartPosition = Utils.findLabelFramePositionFromName(dateMovieClip.labels, "page_flip");
        dateMovieClip.addAction(() => {
            jibo.sound.play('sfxCalendarPaperFlips');
        }, pageFlipAnimationStartPosition);

        PIXI.animate.Animator.play(dateMovieClip, "date_in", ()=>{
            callback();
        });
    }

    update() {
        try {
            if(this._dateMim) {
                this._dateMim.update();
            }
        } catch(err) {
            this.log.error(err);
        }
    }

    animateOut(timedOut, dateMovieClip, animationFinishedCallback) {
        if((!timedOut && this._swipeDown && this._context === Contexts.Menu) || !this._dateView) {
            // do not play the animation back to idle because we're going to be transitioning back to the menu
            animationFinishedCallback();
        }
        else {
            // date to idle animation
            this._dateView.lockInput(true);
            jibo.sound.play('sfxCalendarOut');
            PIXI.animate.Animator.play(dateMovieClip, "date_out", animationFinishedCallback);
        }
    }

    setContent(movieClip) {
        let currentTime = new BeFramework.utils.DateTime(null, null, this._location.timezone);
        let localTime = currentTime.getLocalTime();

        // let beforeNumberSuffixDelta = findDeltaBetweenDateNumeralAndSuffix(movieClip);
        // figure out what the delta is from the original values from the sample data in the movieClip
        let dayNumberTextLeftPosition = (movieClip.dateNumber.dayNumberText.position.x - (movieClip.dateNumber.dayNumberText.width * movieClip.dateNumber.dayNumberText.anchor.x));
        let dayNumberTextRightPosition = dayNumberTextLeftPosition + movieClip.dateNumber.dayNumberText.width;
        let daySuffixTextLeftPosition =   (movieClip.dateNumber.daySuffixText.position.x - (movieClip.dateNumber.daySuffixText.width * movieClip.dateNumber.daySuffixText.anchor.x));
        let delta = dayNumberTextRightPosition - daySuffixTextLeftPosition;

        movieClip.dateDay.dayText.text = localTime.dayOfWeek.slice(0, 1).toUpperCase() + localTime.dayOfWeek.slice(1);
        movieClip.dateMonth.dateMonthText.text = localTime.month.toUpperCase();
        movieClip.dateNumber.dayNumberText.text = localTime.date;

        let ordinal = BeFramework.utils.DateTimeUtils.getOrdinal(localTime.date);
        movieClip.dateNumber.daySuffixText.text = ordinal.substr(-2);

        // update the daySuffixText position based on the actual assigned values
        dayNumberTextLeftPosition = (movieClip.dateNumber.dayNumberText.position.x - (movieClip.dateNumber.dayNumberText.width * movieClip.dateNumber.dayNumberText.anchor.x));
        dayNumberTextRightPosition = dayNumberTextLeftPosition + movieClip.dateNumber.dayNumberText.width;
        movieClip.dateNumber.daySuffixText.position.x = (dayNumberTextRightPosition - delta) + (movieClip.dateNumber.daySuffixText.width * movieClip.dateNumber.daySuffixText.anchor.x);

        // set up the mim
        if(this._dayOfWeek) {
            this._dateMim = new Mim({
                mimPath: "mims/TodaysDay.mim",
                assetPack: this._assetPack,
                getPromptData: ()=>{
                    return {
                        dayOfWeek: localTime.dayOfWeek
                    };
                }
            });
        } else {
            this._dateMim = new Mim({
                mimPath: "mims/TodaysDate.mim",
                assetPack: this._assetPack,
                getPromptData: ()=>{
                    return {
                        dayOfWeek: localTime.dayOfWeek,
                        month: localTime.month,
                        dateOrdinal: localTime.date,
                        where: this._location
                    };
                }
            });
        }
        this._dateMim.start();
    }

    destroy(timedOut, callback) {
        jibo.timer.removeListener('update', this._updateMethod);
        this._dateView = null;
        Promise.resolve()
        .then(()=>{
            return new Promise((resolve)=>{
                if(this._dateMim) {
                    this._dateMim.stop().then(()=>{
                        this._dateMim.destroy();
                        this._dateMim = null;
                        resolve();
                    });
                } else {
                    resolve();
                }
            });
        })
        .then(()=>{
            let viewOptions = {
                removeAll: true,
                leaveEmpty: true,
                transitionOpen: jibo.face.views.IN,
                transitionClose: this._context !== Contexts.Menu || timedOut || !this._swipeDown ? jibo.face.views.NONE : jibo.face.views.DOWN
            };
            let onFailure = (err) => {
                this.log.warn('View close failure:', err);
                callback();
            }
            this._swipeDown = false;
            jibo.face.views.changeView(viewOptions, callback, onFailure);
        });
    }
}

export default JiboDate;
