import { libraries, utils, BeSkill} from '@be/be-framework';
import JiboClock from './JiboClock';
import JiboDate from './JiboDate';
import MenuSubSkill from './MenuSubSkill';
import JiboBirthday from './JiboBirthday';
import JiboHoliday from './JiboHoliday';
import Utils from './Utils';
import ResultObject from './ResultObject';
import Contexts from './Contexts';
import AlarmTimer from './alarmTimer/AlarmTimer';
import CronJobManager from './CronJobManager';
import Analytics from './analytics/Analytics';

const CancelToken = libraries.jibo_cai_utils.CancelToken;
const CancelTokenSession = libraries.jibo_cai_utils.CancelTokenSession;
const jibo = require('jibo');

class ClockSkill extends BeSkill {
    /**
    * Clock skill constructor
    * @constructor
    * @param {String} [assetPack=''] The asset pack
    */
    constructor(assetPack) {
        super(assetPack);
        this.analytics = new Analytics(this);

        CronJobManager.log = this.log.createChild('CronJobManager');

        this._promiseSession = null;

        this._subSkill = null;

        this._clockDomain = "clock";
        this._timerDomain = "timer";
        this._alarmDomain = "alarm";

        this._menuIntent = "menu";
        this._timeIntent = "askForTime";
        this._dateIntent = "askForDate";
        this._dayIntent = "askForDay";
        this._birthdayIntent = "whenIsBirthday";
        this._holidayIntent = "whenIsHoliday";
        this._finishedIntent = "finished";
        this._stopIntent = "stop";
        this._deleteIntent = "delete";

        this._assetCache = "ClockAssetCache";

        this._skillTimeout = null;
        this._skillTimedOut = false;

        this._exit = this.exit.bind(this);
        this._model = null;
        this._runId = 0;

        this._launchRuleResult = null;
    }

    /**
    * Asynchronous init
    * @method postInit
    */
    postInit(done) {
        jibo.kb.onInit().then(() => {
            this._model = jibo.kb.createModel('/jibo/clock/alarm_timer');
            return CronJobManager.restoreJobs(this._model).then(() => {
                this.log.debug(`restored CronJobs`);
                done();
            });
        }).catch(err => {
            this.log.warn(`Error during postInit:`, err);
            done();
        });
    }

    /**
     * Called just before skill starts
     * @param callback
     */
    preload(callback) {
        // Ensure that the jibo home data matches that in the KB, in case it changed
        utils.Location.jiboHome.fetch(() => {
            callback();
        });
    }

    /**
     * Start the skill
     * @method open
     */
    open(launchRuleResult, refresh, previousSkill, previousLaunchResult) {
        let runId = this._runId++;
        this.log.info("launch skill", runId);
        this._launchRuleResult = launchRuleResult;

        if (launchRuleResult && launchRuleResult.nlu) {
            const currentParse = launchRuleResult.nlu;
            if ((currentParse.entities.domain === this._timerDomain
                || currentParse.entities.domain === this._alarmDomain)
                && currentParse.intent === this._finishedIntent) {
                this._isInterruptible = false;
            } else {
                this._isInterruptible = true;
            }
            this.log.debug('isInterruptible:', this._isInterruptible);

            if (refresh && previousLaunchResult && previousLaunchResult.nlu) {
                const previousParse = previousLaunchResult.nlu;
                if ((previousParse.intent === this._finishedIntent)
                    && ((currentParse.intent === this._stopIntent)
                    || (currentParse.intent === this._deleteIntent))) {
                    this.log.info('Stopping Alarm/Timer by voice');
                    process.nextTick(() => {
                        this.exit({noElementsOfSurprise: true});
                    });
                    return;
                }
            }
        }


        if(this._promiseSession && this._promiseSession.isCanceling()) {
            this.log.info("we're already cancelling. preventing this from cancelling again. however the launch results have been replaced", runId);
            return;
        }

        Promise.resolve()
        .then(()=>{
            if(!this._promiseSession) {
                this._promiseSession = new CancelTokenSession();
            } else {
                this.log.info("cancel promise session", runId);
                return this._promiseSession.cancel();
            }
        })
        .then(()=>{
            if(this._subSkill) {
                return this._promiseSession.wrap(this.closeSubSkill(runId));
            }
        })
        .then(()=>{
            this.log.info("getting skill", runId);
            return this._promiseSession.wrap(this.getSubSkill(this._launchRuleResult));
        })
        .then((subSkill)=>{
            this.log.info("running skill", runId, subSkill.name);
            this._subSkill = subSkill;
            return this._promiseSession.wrap(this.runSubSkill(subSkill));
        })
        .then((subSkill)=>{
            // wait X amount of time to allow the skill to run.
            // if by the end of that time the skill passed to this callback isn't the same as what was set to this._subSkill
            // call reject and don't try to shutdown the subSkill again
            this._skillTimedOut = false;
            return this._promiseSession.wrap(new Promise((resolve, reject)=>{
                this.log.info("waiting for skill timeout", runId, subSkill.name);

                let startTime = Date.now();
                this._skillTimeout = jibo.timer.setInterval(()=>{

                    // times up!
                    if(subSkill.hasTimedOut(startTime)) {
                        // Date.now() - startTime >= subSkill.timeoutMS) {
                        this._skillTimedOut = true;
                        this._destroyInterval();
                        if(subSkill === this._subSkill) {
                            return resolve(subSkill);
                        } else {
                            return reject("subskill already shutdown");
                        }
                    }
                    else if(this._promiseSession.isCanceling()) {
                        this.log.info("skill runtime is getting canceled", runId);
                        this._destroyInterval();
                        return resolve(subSkill);
                    }

                }, 10);

            }));
        })
        .catch((reason)=>{
            this.log.error(reason);
        })
        .then(()=>{
            this.log.info("exiting clock skill", runId);
            try {
                this.exit();
            } catch(err) {
                this.log.error("exiting clock failed", err);
            }
        });
    }

    getSubSkill(launchRuleResult) {
        return new Promise((resolve, reject)=>{
            try {
                let context = this.getContext(launchRuleResult);
                if(launchRuleResult && launchRuleResult.nlu) {
                    let city = launchRuleResult.nlu.entities.city !== "null" ? launchRuleResult.nlu.entities.city : null;
                    let state = launchRuleResult.nlu.entities.state !== "null" ? launchRuleResult.nlu.entities.state : null;
                    let country = launchRuleResult.nlu.entities.country !== "null" ? launchRuleResult.nlu.entities.country : null;
                    let dayOfWeek = launchRuleResult.nlu.entities.day_of_week !== "null" ? launchRuleResult.nlu.entities.day_of_week : null;
                    let loopMemberReferent = launchRuleResult.nlu.entities.loopMemberReferent !== "null" ? launchRuleResult.nlu.entities.loopMemberReferent : null;
                    let speaker = launchRuleResult.nlu.entities.loopmember;
                    let loopMember = speaker || loopMemberReferent;
                    let holiday = launchRuleResult.nlu.entities.holiday !== "null" ? launchRuleResult.nlu.entities.holiday : null;
                    this.log.debug('result.nlu:', launchRuleResult.nlu);

                    // check the domain on the nlu object to switch into the various parts of the clock skill
                    switch(launchRuleResult.nlu.entities.domain) {
                        case this._clockDomain: {
                            // both the date and the time have the same domain
                            // switch on the nlu intent
                            switch(launchRuleResult.nlu.intent) {
                                case this._dayIntent:
                                case this._dateIntent: {
                                    let date = new JiboDate(this, this.assetPack, context);
                                    date.init(city, state, country, dayOfWeek, (err)=>{
                                        if(err) {
                                            reject(err);
                                        } else {
                                            resolve(date);
                                        }
                                    });
                                    break;
                                }
                                case this._timeIntent: {
                                    let clock = new JiboClock(this, this.assetPack, context);
                                    clock.init(city, state, country, (err)=>{
                                        if(err) {
                                            reject(err);
                                        } else {
                                            resolve(clock);
                                        }
                                    });
                                    break;
                                }
                                case this._birthdayIntent: {
                                  let birthdaySkill = new JiboBirthday(this, this.assetPack);
                                  birthdaySkill.init(loopMember, ()=>{
                                    resolve(birthdaySkill);
                                  });
                                  break;
                                }
                                case this._holidayIntent: {
                                  let holidaySkill = new JiboHoliday(this, this.assetPack);
                                  holidaySkill.init(holiday, ()=>{
                                    resolve(holidaySkill);
                                  });
                                  break;
                                }
                                default:
                                case this._menuIntent: {
                                    let menu = new MenuSubSkill(this, this.assetPack, context, this.refresh.bind(this));
                                    resolve(menu);
                                    break;
                                }
                            }
                            break;
                        }
                        case this._timerDomain:
                        case this._alarmDomain: {
                            // Need to handle head touch and 'hey jibo' because the
                            // skill is uninterruptible if the alarm/timer is going off
                            // Need to pass launchRuleResult for analytics
                            this._handleHeadTouch = this.handleHeadTouch.bind(this, launchRuleResult);
                            this._handleHJ = this.handleHJ.bind(this, launchRuleResult);

                            jibo.system.events.touchOn.on(this._handleHeadTouch);
                            jibo.jetstream.events.hjHeard.on(this._handleHJ);

                            let resultObject = this.createTimeObject(launchRuleResult);
                            let domainIsTimer = resultObject.domain === this._timerDomain;
                            let alarmTimer = new AlarmTimer(this, this.assetPack, resultObject, domainIsTimer, this._model, context, null);
                            resolve(alarmTimer);
                            break;
                        }
                        default: {
                            this.log.error("domain field not set for input: " + launchRuleResult.asr.text);
                            reject("domain field not set for input: " + launchRuleResult.asr.text);
                            break;
                        }
                    }
                } else {
                    this.log.info("no nlparse obj. launching menu");
                    let menu = new MenuSubSkill(this, this.assetPack, context, this.refresh.bind(this));
                    resolve(menu);
                }
            } catch(err) {
                reject(err);
            }
        });
    }

    getContext(launchRule) {
        if(launchRule && Boolean(launchRule.context)) {
            return ClockSkill.Contexts[launchRule.context] || null;
        }
        return null;
    }

    runSubSkill(subSkill) {
        return new Promise((resolve, reject)=>{
            try {
                subSkill.run()
                .then(()=>{
                    resolve(subSkill);
                })
                .catch((err)=>{
                    reject(err);
                });
            }
            catch(err) {
                reject(err);
            }
        });
    }

    createTimeObject(result) {
        try {
            const entities = result.entities || result.nlu.entities
            return new ResultObject(
                entities.domain,
                result.intent || result.nlu.intent,
                entities.hours !== "null" ? parseInt(entities.hours) : null,
                entities.minutes !== "null" ? parseInt(entities.minutes) : null,
                entities.seconds !== "null" ? parseInt(entities.seconds) : null,
                entities.time !== "null" ? entities.time : null,
                entities.ampm !== "null" ? entities.ampm : null
            );
        } catch(err) {
            this.log.error(err);
            return null;
        }
    }

    animateOutSubSkill(subSkill) {
        return new Promise((resolve, reject)=>{
            try {
                subSkill.animateOut(this._skillTimedOut, subSkill.movieClip, ()=>{
                    resolve(subSkill);
                });
            } catch(err) {
                reject(err);
            }
        });
    }

    // handling head touch and 'hey jibo' with separate methods for analytics
    handleHeadTouch(launchRuleResult) {
        this.handleGlobals(launchRuleResult, 'head');
    }

    handleHJ(launchRuleResult) {
        this.handleGlobals(launchRuleResult, 'speech');
    }

    handleGlobals(launchRuleResult, analyticsModality) {
        // set isInterruptible to true so skill will handle head touch or HJ normally
        this._isInterruptible = true;
        this.log.debug('Skill is interruptible again');
        jibo.jetstream.events.hjHeard.removeListener(this._handleHJ);
        jibo.system.events.touchOn.removeListener(this._handleHeadTouch);
        jibo.globalEvents.shared.nonInterruptingGlobal.emit();
        let nlu = launchRuleResult.nlu;
        let domain = nlu.entities.domain;
        let intent = nlu.intent;
        if (intent === this._finishedIntent) {
            this.analytics.alarmTimerStopped(domain, analyticsModality);
        }
    }

    /**
    * Stop and unload the skill
    * @method close
    */
    close(callback) {
        this.log.info("closing clock");

        Promise.resolve()
        .then(()=>{
            if(this._promiseSession) {
                return this._promiseSession.cancel();
            }
        })
        .then(()=>{
            // this shouldn't need to be wrapped in the promise session because Be should
            // guarantee that the close method is never called twice or interrupting itself
            this.closeSubSkill("shutdown")
            .catch((err) => {
                // error might be null if rejected with no data
                if (err) {
                    this.log.error(err);
                    return err;
                }
            })
            .then((err) => {
                this._promiseSession = null;
                callback(err);
            });
        })
    }

    _destroyInterval() {
        if(this._skillTimeout) {
            this._skillTimeout.destroy();
            this._skillTimeout = null;
        }
    }

    closeSubSkill(runId) {
        return new Promise((resolve, reject)=>{
            let skill = this._subSkill;

            try {
                this.log.info("shut down skill", runId);
                this._destroyInterval();

                jibo.system.events.touchOn.removeListener(this._handleHeadTouch);
                jibo.jetstream.events.hjHeard.removeListener(this._handleHJ);

                if(skill) {
                    this.log.info("skill animate out", runId);
                    skill.animateOut(this._skillTimedOut, skill.movieClip, ()=>{
                        this.log.info("skill destroy", runId);
                        skill.destroy(this._skillTimedOut, ()=>{
                            this.log.info("skill destroy success", runId);
                            this._subSkill = null;
                            resolve();
                        });
                    });
                } else {
                    this._subSkill = null;
                    resolve();
                }
            }
            catch(err) {
                this._subSkill = null;
                reject(err);
            }
        });
    }
}

ClockSkill.Contexts = Contexts;

ClockSkill.AlarmTimer = AlarmTimer;
ClockSkill.BeSkill = BeSkill;
ClockSkill.JiboClock = JiboClock;
ClockSkill.JiboDate = JiboDate;
ClockSkill.MenuSubSkill = MenuSubSkill;
ClockSkill.JiboBirthday = JiboBirthday;
ClockSkill.JiboHoliday = JiboHoliday;
ClockSkill.Utils = Utils;

module.exports = ClockSkill;
