export default class CronJobManager {

    static log = null;

    static addJob(cronString, eruptData, domainString, KBModel) {
        // Add job to scheduler, save parameters and jobID into kb
        return KBModel.loadRoot().then((rootNode) => {
            return new Promise((resolve, reject) => {
                jibo.scheduler.addJob(cronString, eruptData, (err, jobID) => {
                    if (err) {
                        return reject(err);
                    } else {
                        // add jobID and cronString to KB (create timer/alarm on KB if necessary)
                        if (!rootNode.data[domainString]) {
                            rootNode.data[domainString] = {};
                        }
                        rootNode.data[domainString].jobID = jobID;
                        rootNode.data[domainString].cronString = cronString;
                        rootNode.save().then(() => {
                            CronJobManager.log.info(`added cronJob ${jobID}`);
                            resolve(jobID);
                        });
                    }
                });
            });
        });
    }

    static removeJob(jobID) {
        return this.hasJob(jobID).then((hasJobBoolean) => {
            if (!hasJobBoolean) {
            } else {
                jibo.scheduler.removeJob(jobID, (err) => {
                    if (err) {
                        return Promise.reject(err);
                    }
                    CronJobManager.log.info(`removed cronJob ${jobID}`);
                });
            }
        })
    }

    static hasJob(jobID) {
        return new Promise((resolve, reject) => {
            jibo.scheduler.hasJob(jobID, (err, data) => {
                if (err) {
                    return reject(err);
                }
                resolve(!!data);
            });
        });
    }

    static restoreJobs(KBModel) {
        // If SSM restarts, any scheduled jobs are lost. Need to restore lost jobs from KB
        return KBModel.loadRoot().then((rootNode) => {
            let data = rootNode.data;
            let alarm = data.alarm;
            let timer = data.timer;
            let alarmJobPromise = null;
            let timerJobPromise = null;
            if (alarm && alarm.jobID) {
                if (!alarm.dateTimeInstance || alarm.dateTimeInstance.utc < Date.now()) {
                    alarmJobPromise = this.removeJob(alarm.jobID).then(() => {
                        CronJobManager.log.info(`clearing alarm KB data:`, alarm);
                        delete data.alarm;
                    });
                } else {
                    // If job isn't scheduled but there's a job on the KB, recreate job
                    alarmJobPromise = this.checkForMissingCronJob(alarm, 'alarm', KBModel).then((jobID) => {
                        // jobID will be different, so update the KB
                        CronJobManager.log.info(`restoring cronJob. Old: ${alarm.jobID} | New: ${jobID}`);
                        alarm.jobID = jobID;
                    });
                }
            } else {
                alarmJobPromise = Promise.resolve();
            }
            if (timer && timer.jobID) {
                if (timer.endTime < Date.now()) {
                    timerJobPromise = this.removeJob(timer.jobID).then(() => {
                        CronJobManager.log.info(`clearing timer KB data:`, timer);
                        delete data.timer;
                    });
                } else {
                    // If job isn't scheduled but there's a job on the KB, recreate job
                    timerJobPromise = this.checkForMissingCronJob(timer, 'timer', KBModel).then((jobID) => {
                        // jobID will be different, so update the KB
                        CronJobManager.log.info(`restoring cronJob. Old: ${timer.jobID} | New: ${jobID}`);
                        timer.jobID = jobID;
                    });
                }
            } else {
                timerJobPromise = Promise.resolve();
            }
            return Promise.all([alarmJobPromise, timerJobPromise]).then(()=>{
                return rootNode.save();
            });
        });
    }

    static checkForMissingCronJob(domain, domainString, KBModel) {
        return this.hasJob(domain.jobID).then((hasJobBoolean) => {
            if (!hasJobBoolean) {
                let eruptData = { skill: '@be/clock', domain: domainString, intent: 'finished' };
                return this.addJob(domain.cronString, eruptData, domainString, KBModel);
            }
        });
    }
}
