import {BeSkill} from '@be/be-framework';

type AlarmTimer = 'alarm'|'timer';

export default class Analytics {
    private skill:BeSkill;

    constructor(skill:BeSkill) {
        this.skill = skill;
    }

    public currentTime(other_timezone:boolean) {
        this.skill.track('Clock Query Current Time', { other_timezone });
    }

    public currentDate(other_timezone:boolean) {
        this.skill.track('Clock Query Current Date', { other_timezone });
    }

    public setAlarmTimer(category:AlarmTimer, already_has_alarmTimer:boolean) {
        this.skill.track('Clock Set AlarmTimer', { category, already_has_alarmTimer });
    }

    public queryAlarmTimer(category:AlarmTimer) {
        this.skill.track('Clock Query AlarmTimer', { category });
    }

    public alarmTimerStopped(category:AlarmTimer, modality:'head'|'speech'|'gui') {
        this.skill.track('Clock AlarmTimer Stopped', { category, modality });
    }

    public alarmTimerTimeout(category:AlarmTimer) {
        this.skill.track('Clock AlarmTimer Timeout', { category });
    }

    public editAlarmTimer(category:AlarmTimer) {
        this.skill.track('Clock Edit AlarmTimer', { category });
    }

    public deleteAlarmTimer(category:AlarmTimer) {
        this.skill.track('Clock Delete AlarmTimer', { category });
    }

    public alarmTime(alarm_hour:number) {
        // alarm_hour has already been timezone offset
        this.skill.track('Clock Alarm Hour', { alarm_hour });
    }

    timerDuration(durationMS:number) {
        // convert duration to minutes, round seconds up
        let duration_in_minutes:number = Math.ceil(durationMS / 1000 / 60);
        this.skill.track('Clock Timer Duration', { duration_in_minutes });
    }

    public queryHoliday(holiday_name:string, time_to_holiday:number) {
        this.skill.track('Clock Query Holiday', { holiday_name, time_to_holiday });
    }
}
