import SubSkill from '../SubSkill';
import Contexts from '../Contexts';
import * as BeFramework from '@be/be-framework';
import Timer from './Timer';
import Alarm from './Alarm';
import AlarmTimerUtils from './AlarmTimerUtils';
import AlarmEditGUIView from './AlarmEditGUIView';
import TimerEditGUIView from './TimerEditGUIView';
import CronJobManager from '../CronJobManager';

const ActionData = jibo.rendering.gui.actions.ActionData;
const alarmTimerFlow = require('../flows/alarmTimerMain');

class AlarmTimer extends SubSkill {
    constructor(clockSkill, assetPack, resultObject, domainIsTimer, KBModel, context=null, flowOverrides=null) {
        super();
        this.log = clockSkill.log.createChild('AlarmTimer');

        this._flow = null;
        this._flowRunning = false;
        this._flowOverrides = flowOverrides;

        this._clockSkill = clockSkill;
        this._assetPack = assetPack;
        this._context = context;
        this._domain = resultObject.domain;
        this._domainIsTimer = domainIsTimer;
        this._otherDomain = domainIsTimer ? AlarmTimerUtils.Domains.ALARM : AlarmTimerUtils.Domains.TIMER;
        this._intent = resultObject.intent;
        this._result = resultObject;

        // This sets this._ampm and this._time
        this.sanitizeInput(resultObject.ampm, resultObject.time);

        this._dateTimeInstance = null;

        this._hours = resultObject.hours;
        this._minutes = resultObject.minutes;
        this._seconds = resultObject.seconds;
        this._timerEndTime = null;
        this._timerLength = null;

        this.swipeDown = false;
        this.refreshWithMenuIntent = this.refreshWithMenuIntent.bind(this);

        this._addViewOptions = {
            addView: `resources/views/${this._domain}.json`,
            transitionOpen: jibo.face.views.IN,
            transitionClose: jibo.face.views.OUT
        };

        this._model = KBModel;
        this._rootNode = null;

        this.alarmTimerMovieClip = null;

        this._isErupting = false;
        this._eruptData = { skill: '@be/clock', domain: this._domain, intent: 'finished' };
        this._playback = null;

        this._domainInstance = null;
        this._otherDomainInstance = null;
    }

    get name() {
        return "AlarmTimer";
    }

    hasTimedOut(startTime) {
        if(this._flow) {
            return !this._flowRunning;
        } else {
            return Date.now() - startTime >= 50;
        }
    }

    get movieClip() {
        return this.alarmTimerMovieClip;
    }

    get otherDomainSet() {
        return this._domainIsTimer ? !!this._rootNode.data.alarm : !!this._rootNode.data.timer;
    }

    get promptTime() {
        return this._domainInstance.promptTime;
    }

    get ampmBoolean() {
        return !!this._domainInstance.dateTimeInstance.getLocalTime();
    }

    run() {
        return this._model.loadRoot().then((rootNode) => {
            this._rootNode = rootNode;
            this.queryLocalRootNode();
            this._domainInstance = this._domainIsTimer ? new Timer(this) : new Alarm(this);
            if (this._intent === 'stop' || this._intent === 'delete') {
                this._otherDomainInstance = !this._domainIsTimer ? new Timer(this) : new Alarm(this);
            }
            jibo.face.views.creator.registerClass(AlarmEditGUIView, 'AlarmEditGUIView');
            jibo.face.views.creator.registerClass(TimerEditGUIView, 'TimerEditGUIView');
        }).then(() => {
            // analytics
            switch (this._intent) {
                case 'set':
                case 'start': {
                    this._clockSkill.analytics.setAlarmTimer(this._domain, !!this._rootNode.data[this._domain]);
                    break;
                }
                case 'query': {
                    this._clockSkill.analytics.queryAlarmTimer(this._domain);
                    break;
                }
                case 'stop':
                case 'delete': {
                    this._clockSkill.analytics.deleteAlarmTimer(this._domain);
                    break;
                }
            }

            return new Promise((resolve) => {
                let options = Object.assign(
                    {
                        enableLogging: true,
                        assetPack: this._assetPack,
                        blackboard: {
                            alarmTimer: this,
                            analytics: this._clockSkill.analytics,
                            log: this.log,
                        },
                    },
                    this._flowOverrides);
                this._flowRunning = true;
                this._flow = jibo.flow.run(alarmTimerFlow, options, () => {
                    this._flowRunning = false;
                });
                resolve(this._flow);
            });
        });
    }

    queryLocalRootNode() {
        const data = this._rootNode.data;
        const alarm = data.alarm;
        const timer = data.timer;
        if (alarm) {
            if (!alarm.dateTimeInstance || alarm.dateTimeInstance.utc < Date.now()) {
                CronJobManager.removeJob(alarm.jobID).then(() => {
                    this.log.debug(`clearing alarm KB data:`, alarm);
                    delete data.alarm;
                    this._rootNode.save();
                });
            } else {
                this.log.debug(`getting alarm KB data:`, alarm);
                this._dateTimeInstance = new BeFramework.utils.DateTime(alarm.dateTimeInstance);
            }
        }
        if (timer) {
            if (timer.endTime < Date.now()) {
                CronJobManager.removeJob(timer.jobID).then(() => {
                    this.log.debug(`clearing timer KB data:`, timer);
                    delete data.timer;
                    this._rootNode.save();
                })
            } else {
                this.log.debug(`getting timer KB data:`, timer);
                this._timerEndTime = timer.endTime;
                this._timerLength = timer.length;

                let remainingMS = this._timerEndTime - Date.now();
                this._hours = Math.floor(remainingMS / 1000 / 60 / 60);
                this._minutes = Math.floor((remainingMS / 1000 / 60) % 60);
                this._seconds = Math.floor((remainingMS / 1000) % 60);
            }
        }
    }

    sanitizeInput(ampm, time) {
        if (time && time.endsWith('M') && !ampm) {
            this._ampm = time.slice(-2);
            this._time = time.slice(0, time.length - 2);
        } else {
            this._ampm = ampm;
            this._time = time;
        }
    }

    addToScheduler() {
        return CronJobManager.addJob(this._domainInstance.cronString, this._eruptData, this._domain, this._model);
    }

    addToKB() {
        return this._domainInstance.addToKB();
    }

    isCurrentDomainSet() {
        this.queryLocalRootNode();
        return !!this._rootNode.data[this._domain];
    }

    valueAtLaunch() {
        return this._domainInstance.valueAtLaunch();
    }

    isRangeUnder24Hrs(launchResult) {
        return this._domainInstance.isRangeUnder24Hrs(launchResult);
    }

    isRangeOver5Seconds(launchResult) {
        return this._domainInstance.isRangeOver5Seconds(launchResult);
    }

    setGuiData(kbOrResult) {
        this._domainInstance.setGuiData(kbOrResult);
    }

    start() {
        this._domainInstance.start();
    }

    durationAnalytics() {
        this._domainInstance.durationAnalytics(this._clockSkill.analytics);
    }

    displayNewSetTime() {
        this.log.debug(`display ${this._domain} view`);
        return this._domainInstance.gui.displayNewSetTime().then(() => {
            if (jibo.face.views.currentView) {
                jibo.face.views.currentView.removeAllListeners('swipeDown');
                jibo.face.views.currentView.on('swipeDown', () => {
                    this.log.info(`user swiped down on ${this._domain} view`);
                    this.swipeDown = true;
                });
            }
        });
    }

    handleViewError(err) {
        if (err) {
            this.log.error(err);
        } else {
            // If we don't get an error message from the viewManager, the view change
            // failed because there was a handleable interruption, so just log a warning
            this.log.warn('View interrupted');
        }
    }

    displayOtherDomain() {
        // This is for AlarmTimerCancel, in the case where user asks to cancel
        // Alarm, but Timer is set and vice versa. Need to switch domains to
        // display other movieClip and update the correct KB/scheduler data.
        this._addViewOptions.addView = `resources/views/${this._otherDomain}.json`;
        this._domainInstance = this._otherDomainInstance;
        this._domain = this._otherDomain;
        return this.displayNewSetTime();
    }

    changeAlarmTimer(clearDataBoolean) {
        this.log.info(`changing ${this._domain} time`);
        if (clearDataBoolean) {
            this.clearLaunchResultValues();
        }
        return this._domainInstance.changeTime(clearDataBoolean, this._result)
    }

    clearLaunchResultValues() {
        this.log.info(`clearing result values`);
        this._result.hours = null;
        this._result.minutes = null;
        this._result.seconds = null;
        this._result.time = null;
        this._result.ampm = null;
    }

    createTimeObject(result) {
        return this._clockSkill.createTimeObject(result);
    }

    cleanUpTimers() {
        if(this._eruptTimeout) {
            jibo.timer.clearTimeout(this._eruptTimeout);
        }
        if(this._playback) {
            this._playback.stop();
            this._playback = null;
        }
        if (this._domainInstance && this._domainInstance.gui) {
            this._domainInstance.gui.cleanUpTimers();
        }
    }

    closeSubFlow() {
        this.cleanUpTimers();
        if (this.swipeDown && this._context === Contexts.Menu) {
            this.refreshWithMenuIntent();
        }
    }

    erupt() {
        return new Promise((resolve, reject) => {
            this.log.info(`${this._domain} erupting...`);
            this._isErupting = true;
            if (jibo.face.views.currentView &&
                    (jibo.face.views.currentView.id === 'alarmView' ||
                    jibo.face.views.currentView.id === 'timerView' ||
                    jibo.face.views.currentView.id === 'mimMenu' ||
                    jibo.face.views.currentView.id === 'alarmEditView' ||
                    jibo.face.views.currentView.id === 'timerEditView'))
                {
                this.cleanUpTimers();
                this._clockSkill.refresh({
                    nlu: {
                        entities: {
                            domain: this._domain,
                        },
                        intent: this._clockSkill._finishedIntent
                    }
                });
            } else {
                let onViewComplete = (view) => {
                    try {
                        const animDBNames = {
                            ALARM: 'clock-alarm-erupt-01',
                            TIMER: 'clock-timer-erupt-02'
                        };

                        let eruptAnimDBName = this._domainIsTimer ? animDBNames.TIMER : animDBNames.ALARM;

                        const eruptBodyAnim = jibo.animDB.getAnimByName(eruptAnimDBName);
                        const config = {
                            loops: 0,
                            cache: jibo.loader.activeCache
                        };
                        return eruptBodyAnim.createFromConfig(config).then((playback) => {
                            this.log.debug(`playing body animation`, eruptAnimDBName);
                            this._playback = playback;
                            // Start face and audio looping
                            this._playback.instance.events.started.on(() => {
                                this.log.debug(`playing face animation`);
                                if (this.alarmTimerMovieClip && this.alarmTimerMovieClip.labelsMap) {
                                    PIXI.animate.Animator.play(this.alarmTimerMovieClip, `${this._domain}_body_ring`);
                                }
                            });
                            // Start body looping
                            this._playback.play().catch(() => {
                                this.log.error('something went horribly wrong with the alarmTimer animation');
                            });

                            // Timeout after 30 seconds unless stopped with tap, swipedown, 'HJ stop,' or head touch
                            this._eruptTimeout = jibo.timer.setTimeout(() => {
                                resolve('timedOut');
                            }, 30 * 1000);
                        }).catch((err) => {
                            reject(err);
                        });
                    } catch(err) {
                        reject(err);
                    }
                }
                let onViewLoaded = (view) => {
                    try {
                        this.alarmTimerMovieClip = view.getComponentById(`${this._domain}Clip`).movieClip;
                        this.alarmTimerMovieClip.gotoAndStop(`${this._domain}_body_ring`);

                        const touchCallback = () => {
                            resolve('touch');
                        };

                        view.addAction(ActionData.CALLBACK, { callback: touchCallback }, false, true, jibo.face.views.TAP);
                        view.addAction(ActionData.CALLBACK, { callback: touchCallback }, false, true, jibo.face.views.SWIPE);

                        // Set up PIXI animation
                        let timeClip = this.alarmTimerMovieClip.timeClip;
                        if (!this._domainIsTimer) {
                            timeClip.visible = true;
                            // Need to create a new DateTime because instance on KB was cleared during refresh
                            let dt = new BeFramework.utils.DateTime(Date.now(), BeFramework.utils.Location.jiboHome.timezone);
                            let alarmTime = this._domainInstance.convertAlarmTime(dt);
                            timeClip.time.text = alarmTime.time;
                            timeClip.am_pm.text = alarmTime.ampm;
                        }
                        timeClip.question.visible = false;
                        timeClip.tapToEdit.visible = false;

                        // Set up audio to trigger from PIXI label
                        jibo.sound.SoundUtils.addClipSounds(this.alarmTimerMovieClip);
                        jibo.sound.sound(`${this._domain}Ring`).volume = 0.6;
                    } catch(err) {
                        reject(err);
                    }
                }
                jibo.face.views.changeView(this._addViewOptions, onViewComplete, (err) => {
                    return err;
                }, onViewLoaded);
            }
        });
    }

    refreshWithMenuIntent() {
        return new Promise((resolve, reject) => {
            try {
                this._clockSkill.refresh({
                    nlu: {
                        entities: {
                            domain: this._clockSkill._clockDomain,
                        },
                        intent: this._clockSkill._menuIntent
                    },
                    context: Contexts.Timer
                });
                resolve();
            } catch(err) {
                reject(err);
            }
        });
    }

    animateOut(timedOut, alarmTimerMovieClip, animationFinished) {
        animationFinished();
    }

    destroy(timedOut, callback) {
        this.log.info(`destroying...`);
        jibo.face.views.creator.unregisterClass('AlarmEditGUIView');
        jibo.face.views.creator.unregisterClass('TimerEditGUIView');
        this.cleanUpTimers();
        let viewOptions = {
            removeAll: true,
            leaveEmpty: this._isErupting || this._context === Contexts.Menu ? true : false,
            transitionOpen: jibo.face.views.IN,
            transitionClose: this._context === Contexts.Menu && this.swipeDown ? jibo.face.views.DOWN : jibo.face.views.OUT
        };
        if (this.alarmTimerMovieClip) {
            PIXI.animate.Animator.stop(this.alarmTimerMovieClip);
            this.alarmTimerMovieClip = null;
        }
        if (this._domainInstance && this._domainInstance.gui && this._domainInstance.gui._alarmTimerMovieClip) {
            PIXI.animate.Animator.stop(this._domainInstance.gui._alarmTimerMovieClip);
            this._domainInstance.gui._alarmTimerMovieClip = null;
        }
        if (this._isErupting) {
            this._isErupting = false;
        }
        if (this._flow) {
            this._flow.stopAndDestroy().then(() => {
                this._flow = null;

                let onFailure = (err) => {
                    this.log.warn(err);
                    callback();
                };
                jibo.face.views.changeView(viewOptions, callback, onFailure);
            });
        } else if (callback) {
            callback();
        }
    }
}

export default AlarmTimer;
