import * as BeFramework from '@be/be-framework';
import AlarmTimerUtils from './AlarmTimerUtils';

const jibo = require('jibo');
const View = jibo.rendering.gui.views.View;
const ActionData = jibo.rendering.gui.actions.ActionData;

export default class AlarmEditGUIView extends View {
    constructor() {
        super();

        this._dateTimeInstance = new BeFramework.utils.DateTime(null, '12:00PM', BeFramework.utils.Location.jiboHome.timezone);
        this._editClip = null;
    }

    loadData(loadAssetsOnComplete) {
        // If there's data on the KB, populate the GUI with it
        jibo.kb.createModel('/jibo/clock/alarm_timer').loadRoot().then((rootNode) => {
            let data = rootNode.data;
            let alarm = data.alarm;
            if (alarm) {
                if (alarm.dateTimeInstance) {
                    this._dateTimeInstance = new BeFramework.utils.DateTime(alarm.dateTimeInstance);
                }
            }
            super.loadData(loadAssetsOnComplete);
        });
    }

    createDisplay(container, assets) {
        super.createDisplay(container, assets);
        this._editClip = this.getComponentById(`alarmEdit`).movieClip;
        this.setupDisplay();
    }

    actionHandler(action, fromComponent) {
        if (action.type === ActionData.EVENT && action.data.event === 'confirmPress') {
            let hour = this._dateTimeInstance.getLocalTime().hour;
            let minute = this._dateTimeInstance.getLocalTime().minute;
            if (minute < 10) {
                minute = AlarmTimerUtils.ZeroPad + minute;
            }
            const ampm = hour >= 12 ? 'PM' : 'AM';
            if (hour > 12) {
                hour -= 12;
            } else if (hour === 0) {
                hour = 12;
            }
            action = new ActionData(ActionData.UTTERANCE, {
                utterance: {
                    intent: 'alarmValue',
                    entities: {
                        domain: 'alarm',
                        time: `${hour}:${minute}`,
                        ampm
                    }
                }
            });
        } else if (action.type === ActionData.EVENT && action.data.event === 'arrowPress') {
            let dt = this._dateTimeInstance;
            const timeIncrements = [
                AlarmTimerUtils.ConvertToMS.hour,
                AlarmTimerUtils.ConvertToMS.minute * 10,
                AlarmTimerUtils.ConvertToMS.minute
            ];

            if (action.data && action.data.arrow) {
                if (action.data.up) {
                    dt.utc += timeIncrements[action.data.digit];
                } else {
                    dt.utc -= timeIncrements[action.data.digit];
                }
            }

            if (action.data && action.data.hasOwnProperty('am')) {
                if (action.data.am) {
                    if (dt.getLocalTime().hour >= 12) {
                        dt.utc -= (AlarmTimerUtils.ConvertToMS.day / 2);
                    }
                } else {
                    if (dt.getLocalTime().hour < 12) {
                        dt.utc += (AlarmTimerUtils.ConvertToMS.day / 2);
                    }
                }
            }

            // Make sure time is within the next 24 hours
            if (dt.utc < Date.now()) {
                dt.utc += AlarmTimerUtils.ConvertToMS.day;
            }
            if (dt.utc >= Date.now() + AlarmTimerUtils.ConvertToMS.day) {
                dt.utc -= AlarmTimerUtils.ConvertToMS.day;
            }

            this.updateEditGui(dt);
            action = null;
        }
        if (action) {
            super.actionHandler(action, fromComponent);
        }
    }

    setupDisplay() {
        const HIT_AREA_WIDTH = 180;
        const BUTTON_SCALE = 0.5;
        const setButton = this.getComponentById('set_button');
        const cancelButton = this.getComponentById('cancel_button');
        const buttonOffset = (HIT_AREA_WIDTH - setButton.display.width) / 2;
        setButton.display.scale.x = setButton.display.scale.y = BUTTON_SCALE;
        cancelButton.display.scale.x = cancelButton.display.scale.y = BUTTON_SCALE;
        setButton.setupHitArea(new PIXI.Rectangle(buttonOffset, buttonOffset, HIT_AREA_WIDTH / BUTTON_SCALE, HIT_AREA_WIDTH / BUTTON_SCALE));
        cancelButton.setupHitArea(new PIXI.Rectangle(buttonOffset, buttonOffset, HIT_AREA_WIDTH / BUTTON_SCALE, HIT_AREA_WIDTH / BUTTON_SCALE));

        for (let i = 0; i < 3; ++i){
            this.getComponentById('arrow_up_0' + i).setupHitArea(new PIXI.Rectangle(-50, -37, 150, 150));
            let arrowDown = this.getComponentById('arrow_down_0' + i);
            arrowDown.setupHitArea(new PIXI.Rectangle(-50, -37, 150, 150));
            arrowDown.display.rotation = Math.PI;
        }

        const amButton = this.getComponentById('am_button');
        const pmButton = this.getComponentById('pm_button');
        amButton.setupHitArea(new PIXI.Rectangle(0, 0, 220, 150));
        pmButton.setupHitArea(new PIXI.Rectangle(0, 0, 220, 150));
        this.updateEditGui(this._dateTimeInstance);
    }

    updateEditGui(dt) {
        let hour = dt.getLocalTime().hour;

        if (hour >= 12) {
            hour -= 12;
            this._editClip.amLabel.style.fill ='#6E6E80';
            this._editClip.pmLabel.style.fill = '#00D4F0';
        } else {
            this._editClip.amLabel.style.fill = '#00D4F0';
            this._editClip.pmLabel.style.fill ='#6E6E80';
        }
        if (hour === 0) {
            hour = 12;
        }
        let minute = dt.getLocalTime().minute.toString();
        minute = minute < 10 ? AlarmTimerUtils.ZeroPad + minute : minute;

        this._editClip.hourCounter.text = hour;
        this._editClip.minuteTensCounter.text = minute.slice(0,1);
        this._editClip.minuteOnesCounter.text = minute.slice(1);
    }
}
