import * as BeFramework from '@be/be-framework';
import AlarmGUI from './AlarmGUI';
import AlarmTimerUtils from './AlarmTimerUtils';
import AlarmTimerSubClass from './AlarmTimerSubClass';
import CronJobManager from '../CronJobManager';

class Alarm extends AlarmTimerSubClass {
    constructor(alarmTimer) {
        super();
        this.log = alarmTimer.log;
        this._context = alarmTimer._context;
        this._result = alarmTimer._result;

        this.time = alarmTimer._time;
        this.ampm = alarmTimer._ampm;
        this.dateTimeInstance = alarmTimer._dateTimeInstance || this.createDateTimeInstance();

        this._model = alarmTimer._model;

        let { time, ampm } = this.convertAlarmTime(this.dateTimeInstance);
        this.gui = new AlarmGUI(alarmTimer._addViewOptions, time, ampm, this._context);
    }

    get cronString() {
        let seconds = this.dateTimeInstance.getLocalTime().seconds;
        let minute = this.dateTimeInstance.getLocalTime().minute;
        let hour = this.dateTimeInstance.getLocalTime().hour;
        let date = this.dateTimeInstance.getLocalTime().date;
        let monthNum = this.dateTimeInstance.getLocalTime().monthNum + 1; // monthNum is 0 based index, cronJob expects a 1 based index
        // cronJob format: `* * * * * *`
        return `${seconds} ${minute} ${hour} ${date} ${monthNum} *`;
    }

    get promptTime() {
        return this.dateTimeInstance;
    }

    addToKB() {
        if (this.dateTimeInstance && this.dateTimeInstance.utc > Date.now() + AlarmTimerUtils.ConvertToMS.day) {
            return;
        }
        return this._model.loadRoot().then((rootNode) => {
            if (!rootNode.data.alarm) {
                rootNode.data.alarm = {};
            }
            if (this.dateTimeInstance) {
                rootNode.data.alarm.dateTimeInstance = this.dateTimeInstance;
                this.log.info(`updating alarm KB data:`, rootNode.data.alarm);
            }
            return rootNode.save();
        });
    }

    durationAnalytics(analytics) {
        if (this.dateTimeInstance) {
            analytics.alarmTime(this.dateTimeInstance.getLocalTime().hour);
        }
    }

    changeTime(clearDataBoolean, result) {
        return this._model.loadRoot().then((rootNode) => {
            if (rootNode.data.alarm && rootNode.data.alarm.jobID) {
                return CronJobManager.removeJob(rootNode.data.alarm.jobID).then(() => {
                    delete rootNode.data.alarm;
                    return rootNode.save();
                });
            }
        }).then(() => {
            this.time = clearDataBoolean ? null : result.time;
            this.ampm = clearDataBoolean ? null : result.ampm;
            this.dateTimeInstance = null;

            this.dateTimeInstance = this.createDateTimeInstance();
            let { time, ampm } = this.convertAlarmTime(this.dateTimeInstance);
            this.gui.changeTime(time, ampm);

            return this.addToKB();
        });
    }

    createDateTimeInstance(kbOrResult) {
        if (!kbOrResult) {
            kbOrResult = this;
        }
        if (!kbOrResult.time) {
            kbOrResult.dateTimeInstance = null;
            return;
        }

        let dt = new BeFramework.utils.DateTime(null, kbOrResult.time + (kbOrResult.ampm || ''), BeFramework.utils.Location.jiboHome.timezone);

        // DateTime converts times before 5:59 into PM automatically,
        // so when reading from the KB (which doesn't include AM/PM
        // in kbOrResult.time) it automatically converts to PM 24hour
        // values. This is to catch that and convert back to AM.
        if (dt.getLocalTime().hour >= 12 && kbOrResult.ampm === 'AM') {
            let date = new Date(dt.utc + dt.timezone.offsetUTC);
            date.setUTCHours(date.getUTCHours() - 12);
            dt.utc = date.getTime() - dt.timezone.offsetUTC;
        }

        // DateTime assumes if you say AM you mean today,
        // this sets it to tomorrow.
        if (dt.utc < Date.now() && kbOrResult.time[0] !== '-') {
            let date = new Date(dt.utc + dt.timezone.offsetUTC);
            date.setUTCDate(date.getUTCDate() + 1);
            dt.utc = date.getTime() - dt.timezone.offsetUTC;
        }

        return dt;
    }

    convertAlarmTime(dt) {
        let ampm;
        let time;
        if (!dt || dt.utc >= Date.now() + AlarmTimerUtils.ConvertToMS.day) {
            return {time, ampm};
        }

        let minute = dt.getLocalTime().minute;
        let hour = dt.getLocalTime().hour;

        ampm = hour >= 12 ? 'PM' : 'AM';

        if (hour > 12) {
            hour -= 12;
        } else if (hour === 0) {
            hour = 12;
        }

        minute = minute < 10 ? AlarmTimerUtils.ZeroPad + minute : minute;

        time = `${hour}:${minute}`;

        return {time, ampm};
    }

    isRangeUnder24Hrs(launchResult) {
        let alarmLength = launchResult ? this.createDateTimeInstance(launchResult).utc - Date.now() : this.dateTimeInstance.utc - Date.now();
        return alarmLength <= AlarmTimerUtils.ConvertToMS.day;
    }

    isRangeOver5Seconds(launchResult) {
        let alarmLength = launchResult ? this.createDateTimeInstance(launchResult).utc - Date.now() : this.dateTimeInstance.utc - Date.now();
        return alarmLength > 5 * AlarmTimerUtils.ConvertToMS.second;
    }

    setGuiData(kbOrResult) {
        let dt = null;
        if (!kbOrResult) {
            kbOrResult = this;
            dt = this.dateTimeInstance;
        } else {
            dt = this.createDateTimeInstance(kbOrResult);
        }
        let { time, ampm } = this.convertAlarmTime(dt);
        this.gui.changeTime(time, ampm);
    }

    start() {
        return;
    }

    valueAtLaunch() {
        return !!this._result.time;
    }
}

export default Alarm;
