class RadialMask {
    constructor(radius, initialPercentage) {
      this.radius = radius;
      this.mask = new PIXI.Graphics();
      this.updateMask(initialPercentage);
    }


    updateMask(percentage){
      this.mask.clear();
      this.mask.beginFill(0x000000);
      this.mask.moveTo(0, 0);
      this.mask.lineTo(this.radius, 0);
      this.mask.arc(0, 0, this.radius, 0, Math.PI * 2 * percentage / 100);
      this.mask.endFill();
    }

    dispose() {
      this.mask.destroy();
      this.mask = null;
    }
}

export default RadialMask;
