import SubSkill from './SubSkill';
import * as BeFramework from '@be/be-framework';
const Mim = jibo.bt.behaviors.Mim;

const holidays = require("../resources/holidays/holidays.json");

const HOLIDAY_PASSED_MIM = "mims/HolidayPassed.mim";
const HOLIDAY_JUST_PASSED_MIM = "mims/HolidayJustPassed.mim";
const HOLIDAY_YESTERDAY_MIM = "mims/HolidayYesterday.mim";
const HOLIDAY_TODAY_MIM = "mims/HolidayToday.mim";
const HOLIDAY_TOMORROW_MIM = "mims/HolidayTomorrow.mim";
const HOLIDAY_2TO6_MIM = "mims/Holiday2To6.mim";
const HOLIDAY_7TO13_MIM = "mims/Holiday7To13.mim";
const HOLIDAY_14TO60_MIM = "mims/Holiday14To60.mim";
const HOLIDAY_LATER_MIM = "mims/HolidayLater.mim";
const HOLIDAY_UNKNOWN_MIM = "mims/HolidayUnknown.mim";

class JiboHoliday extends SubSkill {
    /**
    * Create a new JiboHoliday
    * @constructor
    * @param {Object} clockSkill a reference to the clock skill that launched this
    * @param {Object} assetPack Name of the asset pack if running in the context of another skill
    */
    constructor(clockSkill, assetPack) {
        super();
        this.log = clockSkill.log.createChild('Holiday');

        this._clockSkill = clockSkill;
        this._assetPack = assetPack;

        this._holidayMim = null;
        this._holiday = null;

        this._updateMethod = this.update.bind(this);
    }

    get name() {
        return "JiboHoliday";
    }

    hasTimedOut(startTime) {
        if (this._holidayMim) {
            const mimStatus = this._holidayMim.update();
            return mimStatus !== jibo.bt.Status.IN_PROGRESS;
        } else {
            return Date.now() - startTime >= 3000;
        }
    }

    get movieClip() {
        return null;
    }
    /**
    * Initializes the class with params passed from ASR
    * @param {string} holiday the name of the holiday asked for
    * @param {string} city the city of the users current location
    * @param {string} state the state of the users current location
    * @param {string} country the country of the users current location
    * @param {function} callback a callback function for index.js
    */
    init(holiday, callback) {
        this._holiday = holiday;

        jibo.face.views.forceEyeView(() => {
            callback();
        }, (err) => {
            this.log.warn('force eye view error:', err);
            callback();
        });
    }

    run() {
        return new Promise((resolve, reject)=>{
            try {
                this.setContent();
                resolve();
            } catch(err) {
                reject(err);
            }
        });
    }

    animateOut(timedOut, movieClip, animationFinishedCallback) {
        animationFinishedCallback();
    }

    /**
    * Holds the logic for determining when the holiday is in relation to the current date
    * Packages that info and related promptData and sends it to the MIM to start
    */
    setContent() {
        const timezone = BeFramework.utils.Location.jiboHome.timezone;
        let startDate = null;
        let endDate = null;
        let nextYearDate = null;
        let now = new BeFramework.utils.DateTime(Date.now(), timezone).getLocalTime();
        let currentYear = now.year;
        let nextYear = currentYear + 1;
        let startMonth = null;
        let startDay = null;
        let endMonth = null;
        let endDay = null;
        let nextStartMonth = null;
        let nextStartDay = null;
        let nextEndMonth = null;
        let nextEndDay = null;
        let holidayFullName = null;

        function padZeroes(num) {
            if (!num)
                return null;
            if (num < 10) {
                return '0' + num;
            }
            return num.toString();
        }

        try {
            //if we are in January and the holiday starts in December, then use last year's holiday
            if (holidays[currentYear - 1] &&
                holidays[currentYear - 1][this._holiday].month === 12 &&
                now.monthNum === 0) {
                currentYear--;
                nextYear--;
            }
            startMonth = padZeroes(holidays[currentYear][this._holiday].month);
            startDay = padZeroes(holidays[currentYear][this._holiday].day);
            holidayFullName = holidays[currentYear][this._holiday].name;
            //in the data, end dates don't exist - this is fine for now, we don't expect end dates
            //to exist for every holiday anyway
            endMonth = padZeroes(holidays[currentYear][this._holiday].endMonth);
            endDay = padZeroes(holidays[currentYear][this._holiday].endDay);
            nextStartMonth = padZeroes(holidays[nextYear][this._holiday].month);
            nextStartDay = padZeroes(holidays[nextYear][this._holiday].day);
            nextEndMonth = padZeroes(holidays[nextYear][this._holiday].endMonth);
            nextEndDay = padZeroes(holidays[nextYear][this._holiday].endDay);
        }
        catch(err){
            this.log.error(`Insufficient Holiday Data for ${this._holiday}`, err);
        }

        let path = HOLIDAY_UNKNOWN_MIM;

        if (startMonth && startDay && holidayFullName){
            //DateTime accepts 'MM/DD/YYYY' formatted strings
            startDate = new BeFramework.utils.DateTime(`${startMonth}/${startDay}/${currentYear}`, null, timezone);
            //holiday data needs end dates
            if (endMonth && endDay) {
                endDate = new BeFramework.utils.DateTime(`${endMonth}/${endDay}/${currentYear}`, null, timezone);
            } else {
                endDate = startDate;
            }
            nextYearDate = new BeFramework.utils.DateTime(`${nextStartMonth}/${nextStartDay}/${nextYear}`, null, timezone);

            let daysUntilStart = startDate.getRelativeDays();
            let daysUntilEnd = endDate.getRelativeDays();
            this.log.info(`${daysUntilStart} days until ${holidayFullName}`);

            // analytics
            if (daysUntilEnd <= 0 && daysUntilEnd >= -30) {
                this._clockSkill.analytics.queryHoliday(holidayFullName, daysUntilEnd);
            } else if (daysUntilStart >= 0 || daysUntilStart < -30) {
                this._clockSkill.analytics.queryHoliday(holidayFullName, daysUntilStart);
            }

            //handle past holidays
            if (daysUntilEnd <= -4 && daysUntilEnd >= -30) {
                path = HOLIDAY_PASSED_MIM;
            } else if (daysUntilEnd <= -2 && daysUntilEnd >= -3) {
                path = HOLIDAY_JUST_PASSED_MIM;
            } else if (daysUntilEnd == -1) {
                path = HOLIDAY_YESTERDAY_MIM;
            } else {
                //otherwise look into current/future holidays
                if (daysUntilEnd < 0) {
                    //if the end date has already passed but we are here, then we need to look at next year's specifically
                    //this will only be the case if the holiday is 31+ days ago
                    startDate = nextYearDate;
                    if (nextEndMonth && nextEndDay) {
                        endDate = new BeFramework.utils.DateTime(`${nextEndMonth}/${nextEndDay}/${nextYear}`);
                    } else {
                        endDate = startDate;
                    }
                    //recalculate relative days
                    daysUntilStart = startDate.getRelativeDays();
                    daysUntilEnd = endDate.getRelativeDays();
                }
                if (daysUntilEnd === 0 || (daysUntilStart < 0 && daysUntilEnd > 0)){
                    path = HOLIDAY_TODAY_MIM;
                }
                else if (daysUntilStart === 1){
                    path = HOLIDAY_TOMORROW_MIM;
                }
                else if (daysUntilStart > 1 && daysUntilStart < 7){
                    path = HOLIDAY_2TO6_MIM;
                }
                else if (daysUntilStart > 6 && daysUntilStart < 14){
                    path = HOLIDAY_7TO13_MIM;
                }
                else if (daysUntilStart >= 14 && daysUntilStart <= 60){
                    path = HOLIDAY_14TO60_MIM;
                }
                else if (daysUntilStart > 60){
                    path = HOLIDAY_LATER_MIM;
                }
            }
        }
        // set up the mim
        this._holidayMim = new Mim({
            mimPath: path,
            assetPack: this._assetPack,
            getPromptData: ()=>{
                return {
                    //all of the mims now want (up to) 4 things:
                    // - holiday - holiday name
                    // - startDate - starting day of the upcoming holiday (or recently past holiday)
                    // - endDate - ending day of the upcoming holiday (or recently past holiday) - if 1 day holiday, then the same object as startDate
                    // - nextYearDate - starting day of the holiday next year (HolidayJustPassed, HolidayPassed, HolidayYesterday)
                    holiday: holidayFullName,
                    startDate,
                    endDate,
                    nextYearDate
                };
            }
        });
        jibo.timer.on('update', this._updateMethod);
        this._holidayMim.start();
    }

    update() {
        try {
            if(this._holidayMim) {
                this._holidayMim.update();
            }
        } catch(err) {
            this.log.error(err);
        }
    }

    destroy(timedOut, callback) {
        jibo.timer.removeListener('update', this._updateMethod);
        if(this._holidayMim) {
            this._holidayMim.stop()
            .then(()=>{
                this._holidayMim.destroy();
                this._holidayMim = null;
                if (callback){
                    callback();
                }
            });
        } else if (callback){
            callback();
        }
    }
}

JiboHoliday.HOLIDAY_UNKNOWN_MIM = HOLIDAY_UNKNOWN_MIM;
JiboHoliday.HOLIDAY_TODAY_MIM = HOLIDAY_TODAY_MIM;
JiboHoliday.HOLIDAY_TOMORROW_MIM = HOLIDAY_TOMORROW_MIM;
JiboHoliday.HOLIDAY_2TO6_MIM = HOLIDAY_2TO6_MIM;
JiboHoliday.HOLIDAY_7TO13_MIM = HOLIDAY_7TO13_MIM;
JiboHoliday.HOLIDAY_14TO60_MIM = HOLIDAY_14TO60_MIM;
JiboHoliday.HOLIDAY_LATER_MIM = HOLIDAY_LATER_MIM;
JiboHoliday.HOLIDAY_PASSED_MIM = HOLIDAY_PASSED_MIM;
JiboHoliday.HOLIDAY_JUST_PASSED_MIM = HOLIDAY_JUST_PASSED_MIM;
JiboHoliday.HOLIDAY_YESTERDAY_MIM = HOLIDAY_YESTERDAY_MIM;

export default JiboHoliday;
