import * as BeFramework from '@be/be-framework';
import TimerGUI from './TimerGUI';
import AlarmTimerUtils from './AlarmTimerUtils';
import AlarmTimerSubClass from './AlarmTimerSubClass';
import CronJobManager from '../CronJobManager';

class Timer extends AlarmTimerSubClass {
    constructor(alarmTimer) {
        super();
        this.log = alarmTimer.log;

        this.hours = alarmTimer._hours;
        this.minutes = alarmTimer._minutes;
        this.seconds = alarmTimer._seconds;
        this._result = alarmTimer._result;

        this._timerLength = alarmTimer._timerLength || this.getTimerLength();
        this._endTime = alarmTimer._timerEndTime || Date.now() + this._timerLength;

        this._model = alarmTimer._model;
        this.gui = new TimerGUI(alarmTimer, this._endTime, this._timerLength);
    }

    get cronString() {
        if (this._endTime) {
            let endTime = new BeFramework.utils.DateTime(this._endTime, BeFramework.utils.Location.jiboHome.timezone);
            let seconds = endTime.getLocalTime().seconds;
            let minutes = endTime.getLocalTime().minute;
            let hours = endTime.getLocalTime().hour;
            let date = endTime.getLocalTime().date;
            let monthNum = endTime.getLocalTime().monthNum + 1; // monthNum is 0 based index, cronJob expects a 1 based index
            // cronJob format: `* * * * * *`
            return `${seconds} ${minutes} ${hours} ${date} ${monthNum} *`;
        }
    }

    get promptTime() {
        let timeString = '';

        if (this.hours) {
            timeString += this.hours > 1 ? `${this.hours} hours ` : `${this.hours} hour `;
        }
        if (this.minutes) {
            timeString += this.hours && !this.seconds ? 'and ' : '';
            timeString += this.minutes > 1 ? `${this.minutes} minutes ` : `${this.minutes} minute `;
        }
        if (this.seconds) {
            timeString += this.hours || this.minutes ? 'and ' : '';
            timeString += this.seconds > 1 ? `${this.seconds} seconds `: `${this.seconds} second `;
        }
        return timeString;
    }

    addToKB() {
        return this._model.loadRoot().then((rootNode) => {
            if (!rootNode.data.timer) {
                rootNode.data.timer = {};
            }
            rootNode.data.timer.endTime = this._endTime;
            rootNode.data.timer.length = this._timerLength;
            this.log.info(`updating timer KB data:`, rootNode.data.timer);
            return rootNode.save();
        });
    }

    durationAnalytics(analytics) {
        analytics.timerDuration(this._timerLength);
    }

    changeTime(clearDataBoolean, result) {
        this.gui.cleanUpTimers();

        return this._model.loadRoot().then((rootNode) => {
            if (rootNode.data.timer && rootNode.data.timer.jobID) {
                return CronJobManager.removeJob(rootNode.data.timer.jobID).then(() => {
                    delete rootNode.data.timer;
                    return rootNode.save();
                });
            }
        }).then(() => {
            this.hours = clearDataBoolean ? null : result.hours;
            this.minutes = clearDataBoolean ? null : result.minutes;
            this.seconds = clearDataBoolean ? null : result.seconds;

            this._timerLength = this.getTimerLength();
            this._endTime = Date.now() + this._timerLength;
            this.gui.changeTime(this._endTime, this._timerLength);

            return this.addToKB();
        })
    }

    getTimerLength(kbOrResult) {
        if (!kbOrResult) {
            kbOrResult = this;
        }
        let len = kbOrResult.seconds * AlarmTimerUtils.ConvertToMS.second || 0;
        len += kbOrResult.minutes * AlarmTimerUtils.ConvertToMS.minute || 0;
        len += kbOrResult.hours * AlarmTimerUtils.ConvertToMS.hour || 0;
        // Setting this._timerLength to NaN if no timer length is specified
        len = len > AlarmTimerUtils.ConvertToMS.day ? NaN : len;
        len = len || NaN;
        return len;
    }

    isRangeUnder24Hrs(launchResult) {
        let timerLength = launchResult ? this.getTimerLength(launchResult) : this._timerLength;
        return timerLength <= AlarmTimerUtils.ConvertToMS.day;
    }

    isRangeOver5Seconds(launchResult) {
        let timerLength = launchResult ? this.getTimerLength(launchResult) : this._timerLength;
        return timerLength > 5 * AlarmTimerUtils.ConvertToMS.second;
    }

    setGuiData(launchResult) {
        let timerLength = launchResult ? this.getTimerLength(launchResult) : this._timerLength;
        let endTime = launchResult ? Date.now() + this.getTimerLength(launchResult) : this._endTime;
        this.gui.changeTime(endTime, timerLength);
    }

    start() {
        this._endTime = Date.now() + this._timerLength;
        this.gui.changeTime(this._endTime, this._timerLength);
    }

    valueAtLaunch() {
        return !!this._result.hours || !!this._result.minutes || !!this._result.seconds;
    }
}

export default Timer;
