import Contexts from '../Contexts';
import AlarmTimerUtils from './AlarmTimerUtils';
import RadialMask from './RadialMask';

class TimerGUI {
    constructor(alarmTimer, endTime, timerLength) {
        this.log = alarmTimer.log.createChild('timer-gui');
        this._context = alarmTimer._context;
        this._addViewOptions = alarmTimer._addViewOptions;

        this._timerLength = timerLength;
        this._endTime = endTime;
        this._lastCheckTime = -1;

        this._timerState = AlarmTimerUtils.TimerState.over24hrs;
        this._timerUpdateLoop = this._timerUpdateLoop.bind(this);
        this._maskUpdater = null;

        this._alarmTimerMovieClip = null;
        this._alarmTimer = alarmTimer;
    }

    changeTime(endTime, timerLength) {
        this._endTime = endTime;
        this._timerLength = timerLength;
    }

    displayNewSetTime() {
        return new Promise((resolve, reject) => {
            // If the current view is the timer, don't add a new view.
            if (jibo.face.views.currentView && jibo.face.views.currentView.id === 'timerView') {
                this.timerGuiSetup();
                resolve();
            } else {
                if(this._context === Contexts.Menu) {
                    this._addViewOptions.remove = true;
                    this._addViewOptions.transitionClose = jibo.face.views.UP;
                    this._addViewOptions.transitionOpen = jibo.face.views.UP;
                }
                jibo.face.views.changeView(this._addViewOptions, resolve, reject, (view) => {
                    try {
                        this._alarmTimerMovieClip = view.getComponentById(`timerClip`).movieClip;
                        this._alarmTimerMovieClip.gotoAndStop(`timer_in_stop`);

                        view.addAction('event', {event: 'swipeDown'}, true, false, jibo.face.views.SWIPE);
                        view.addAction('mimEnd', null, false, false, jibo.face.views.SWIPE);
                        view.addAction('mimEnd', null, false, false, jibo.face.views.TAP);

                        this.timerGuiSetup();
                    } catch(err) {
                        reject(err);
                    }
                });
            }
        });
    }

    timerGuiSetup() {
        this._alarmTimerMovieClip.time0.visible = false;
        this._timerState = AlarmTimerUtils.TimerState.over24hrs;

        this._maskUpdater = new RadialMask(500, 0.001);
        this._maskUpdater.mask.x = this._alarmTimerMovieClip.loader.loaderFill.x;
        this._maskUpdater.mask.y = this._alarmTimerMovieClip.loader.loaderFill.y;
        this._maskUpdater.mask.rotation = -0.5 * Math.PI;

        this._alarmTimerMovieClip.loader.addChild(this._maskUpdater.mask);
        this._alarmTimerMovieClip.loader.loaderFill.mask = this._maskUpdater.mask;

        jibo.timer.on('update', this._timerUpdateLoop);
    }

    _timerUpdateLoop() {
        try {
            let remainingMS = this._endTime - Date.now();
            let checkTime = Math.ceil(remainingMS / 1000 );
            let timeClip = this._alarmTimerMovieClip.timeClip;

            this.timerRingAnim(remainingMS);

            if (checkTime !== this._lastCheckTime) {
                this._lastCheckTime = checkTime;
                this.timerGuiUpdate();
            }
            if (remainingMS <= 0) {
                this.cleanUpTimers();
                this.erupt();
            }
            // Fast isNaN check
            if (remainingMS !== remainingMS || remainingMS > AlarmTimerUtils.ConvertToMS.day) {
                timeClip.question.alpha = 1;
                this.cleanUpTimers();
            }


        } catch(err) {
            this.log.error(err);
        }
    }

    timerGuiUpdate() {
        let timeClip = this._alarmTimerMovieClip.timeClip;
        let seconds = this._lastCheckTime;

        timeClip.question.alpha = 0;
        timeClip.tapToEdit.alpha = 1;

        if (this._timerState === AlarmTimerUtils.TimerState.over24hrs) {
            // Check to see if we should move to the next state
            if (seconds > 0 && seconds <= 60 * 60 * 24) {
                this._timerState = AlarmTimerUtils.TimerState.over59min;

                timeClip.secondsOnly.alpha = 0;
                timeClip.minutesAndSeconds.alpha = 0;
                timeClip.hoursAndMinutes.alpha = 1;
            } else {
                timeClip.secondsOnly.alpha = 0;
                timeClip.minutesAndSeconds.alpha = 0;
                timeClip.hoursAndMinutes.alpha = 0;
                timeClip.question.alpha = 1;
            }
        }
        if (this._timerState === AlarmTimerUtils.TimerState.over59min) {
            // Check to see if we should move to the next state
            if (seconds < 60 * 60) {
                this._timerState = AlarmTimerUtils.TimerState.over59sec;

                timeClip.hoursAndMinutes.alpha = 0;
                timeClip.minutesAndSeconds.alpha = 1;
            } else {
                let hours = Math.floor(seconds / 60 / 60);
                let minutes = Math.floor((seconds % (60 * 60)) / 60);

                timeClip.hoursAndMinutes.hours.text = hours < 10 ? AlarmTimerUtils.ZeroPad + hours : hours;
                timeClip.hoursAndMinutes.minutes.text = minutes < 10 ? AlarmTimerUtils.ZeroPad + minutes : minutes;
            }
        }
        if (this._timerState === AlarmTimerUtils.TimerState.over59sec) {
            // Check to see if we should move to the next state
            if (seconds < 60) {
                this._timerState = AlarmTimerUtils.TimerState.justSeconds;

                timeClip.minutesAndSeconds.alpha = 0;
                timeClip.secondsOnly.alpha = 1;
            } else {
                let minutes = Math.floor(seconds / 60);
                seconds = Math.floor(seconds % 60);

                timeClip.minutesAndSeconds.minutes.text = minutes < 10 ? AlarmTimerUtils.ZeroPad + minutes : minutes;
                timeClip.minutesAndSeconds.seconds.text = seconds < 10 ? AlarmTimerUtils.ZeroPad + seconds : seconds;
            }
        }
        if (this._timerState === AlarmTimerUtils.TimerState.justSeconds)  {
            seconds = Math.floor(seconds);

            timeClip.secondsOnly.seconds.text = seconds < 10 ? AlarmTimerUtils.ZeroPad + seconds : seconds;
            if (seconds <= 0) {
                timeClip.secondsOnly.seconds.text = AlarmTimerUtils.ZeroPad + AlarmTimerUtils.ZeroPad;
            }
        }
    }

    timerRingAnim(remainingMS) {

        let percentComplete = remainingMS / this._timerLength * 100;

        if (percentComplete <= 0 || percentComplete !== percentComplete) {
            percentComplete = 0;
        }
        this._maskUpdater.updateMask(percentComplete);
    }

    cleanUpTimers() {
        jibo.timer.off('update', this._timerUpdateLoop);
        if (this._alarmTimerMovieClip && this._alarmTimerMovieClip.loader && this._maskUpdater && this._maskUpdater.mask) {
            this._alarmTimerMovieClip.loader.mask = false;
            this._alarmTimerMovieClip.loader.removeChild(this._maskUpdater.mask);
            this._maskUpdater = null;
        }
    }

    erupt(callback) {
        this._alarmTimer.erupt().then(callback);
    }
}

export default TimerGUI;
