import SubSkill from './SubSkill';
import * as BeFramework from '@be/be-framework';

const Mim = jibo.bt.behaviors.Mim;

const BIRTHDAY_TODAY_MIM = "mims/BirthdayToday.mim";
const BIRTHDAY_TOMORROW_MIM = "mims/BirthdayTomorrow.mim"
const BIRTHDAY_2TO6_MIM = "mims/Birthday2To6.mim"
const BIRTHDAY_7TO13_MIM = "mims/Birthday7To13.mim"
const BIRTHDAY_LATER_MIM = "mims/BirthdayLater.mim"
const BIRTHDAY_UNKNOWN_MIM = "mims/BirthdayUnknown.mim"
const BIRTHDAY_ID_UNKNOWN_MIM = "mims/BirthdayIDUnknown.mim"

class JiboBirthday extends SubSkill {
    /**
    * Create a new JiboBirthday
    * @constructor
    * @param {Object} clockSkill a reference to the clock skill that launched this
    * @param {Object} assetPack Name of the asset pack if running in the context of another skill
    */
    constructor(clockSkill, assetPack) {
        super();
        this.log = clockSkill.log.createChild('Birthday');
        this.convTechLog = this.log.createChild('ConvTechSpeakerID');

        this._clockSkill = clockSkill;
        this._assetPack = assetPack;
        this._memberID = null;
        this._loopMember = null;
        this._loopMemberName = null;
        this._loopMemberIsSpeaker = false;

        this._birthdayMim = null;
        this._updateMethod = this.update.bind(this);
    }

    get name() {
        return "JiboBirthday";
    }

    hasTimedOut(startTime) {
        if (this._birthdayMim) {
            const mimStatus = this._birthdayMim.update();
            return mimStatus !== jibo.bt.Status.IN_PROGRESS;
        } else {
            return Date.now() - startTime >= 3000;
        }
    }

    get movieClip() {
        return null;
    }
    /**
    * Initializes the class with params passed from ASR
    * @param {string} loopMember the loop member whose birthday was asked for
    * @param {function} callback a callback function for index.js
    */
    init(loopMember, callback) {
        if (loopMember === 'speaker') {
            this.log.info(`asking for own birthday`);
            let speaker = jibo.lps.identity.getActiveSpeaker();
            if (speaker) {
                let speakerInfo = speaker.idInfo;
                this.convTechLog.info(`Speaker ID: ${speakerInfo.id} | status: ${speakerInfo.status} | confidence: ${speakerInfo.statusConfidence} | score: ${speakerInfo.score}`);
                this._loopMemberIsSpeaker = true;
                this._memberID = speaker.idInfo.id;
            } else {
                this.log.warn('Speaker not IDed!');
                this._memberID = null;
            }
        } else {
            this._memberID = loopMember;
        }

        jibo.face.views.forceEyeView(() => {
            callback();
        }, (err) => {
            this.log.warn('force eye view error:', err);
            callback();
        });
    }

    run() {
        return new Promise ((resolve, reject)=>{
            try {
                Promise.resolve()
                .then(() => {
                    if (this._memberID) {
                        return this.grabUserData()
                        .then(()=>{
                            return this.grabPhoneticName();
                        })
                        .catch((err) => {
                            // if error getting KB data, just set memberID back
                            // to null and act as if ID is unknown in the case
                            // of a deleted loop member whose data still exists
                            this.log.warn(err);
                            this._memberID = null;
                        });
                    }
                })
                .then(()=>{
                    return this.setContent();
                })
                .then(()=>{
                    resolve();
                })
                .catch((err)=>{
                    reject(err);
                });
            }
            catch(err) {
                reject(err);
            }
        });
    }

    animateOut(timedOut, movieClip, animationFinishedCallback) {
        animationFinishedCallback();
    }

    setContent() {
        return new Promise((resolve, reject)=>{
            let birthdayMonth = null;
            let daysUntilBirthday = null;
            let birthdayDay = null;
            let birthdayDayOfWeek = null;

            let birthdayDateTime = null;
            let path = BIRTHDAY_UNKNOWN_MIM;
            try {
                if (!this._memberID) {
                    path = BIRTHDAY_ID_UNKNOWN_MIM;
                }
                if (this._loopMember && this._loopMember.data && this._loopMember.data.birthday){
                    const timezone = BeFramework.utils.Location.jiboHome.timezone;
                    //get current local time for comparison
                    let currentDate = new BeFramework.utils.DateTime(Date.now(), timezone).getLocalTime();
                    //set up birthday for comparisons - UTC methods will return actual local time
                    //according to the timezone, just like DateTime's internal calculations
                    let birthdayDate = new Date (this._loopMember.data.birthday - timezone.offsetUTC);
                    birthdayDate.setUTCFullYear(currentDate.year);

                    //If the loopMembers birthday has passed this year, use next years birthday date
                    if (currentDate.monthNum - birthdayDate.getUTCMonth() > 0 ||
                        (currentDate.monthNum === birthdayDate.getUTCMonth() && currentDate.date - birthdayDate.getUTCDate() > 0)) {
                        birthdayDate.setUTCFullYear(birthdayDate.getUTCFullYear() + 1);
                    }

                    birthdayDateTime = new BeFramework.utils.DateTime(birthdayDate, timezone);
                    birthdayDateTime.stripTime();

                    let birthdayTime = birthdayDateTime.getLocalTime();
                    birthdayMonth = birthdayTime.month;
                    birthdayDay = BeFramework.utils.DateTimeUtils.getOrdinal(birthdayTime.date);
                    birthdayDayOfWeek = birthdayTime.dayOfWeek;
                    daysUntilBirthday = birthdayDateTime.getRelativeDays();

                    if (daysUntilBirthday === 0){
                        path = BIRTHDAY_TODAY_MIM;
                    }
                    else if (daysUntilBirthday === 1){
                        path = BIRTHDAY_TOMORROW_MIM;
                    }
                    else if (daysUntilBirthday > 1 && daysUntilBirthday < 7){
                        path = BIRTHDAY_2TO6_MIM;
                    }
                    else if (daysUntilBirthday > 6 && daysUntilBirthday < 14){
                        path = BIRTHDAY_7TO13_MIM;
                    }
                    else if (daysUntilBirthday >= 14){
                        path = BIRTHDAY_LATER_MIM;
                    }
                }
                //set up the mim
                this._birthdayMim = new Mim({
                    mimPath: path,
                    assetPack: this._assetPack,
                    getPromptData: ()=>{
                        return {
                            loopMember: this._loopMemberName,
                            month: birthdayMonth,
                            day: birthdayDay,
                            dayOfWeek: birthdayDayOfWeek,
                            prefixOnAt: birthdayDateTime ? birthdayDateTime.prefixOnAt() : "",
                            daysUntilBirthday: daysUntilBirthday,
                            loopMemberIsSpeaker: this._loopMemberIsSpeaker
                        };
                    }
                });
                jibo.timer.on('update', this._updateMethod);
                this._birthdayMim.start();
                resolve();
            }
            catch(err){
                reject(err);
            }
        });
    }

    grabUserData(){
        return new Promise((resolve, reject)=>{
            jibo.kb.loop.getUserNodeById(this._memberID, (err, foundMember)=>{
                if (err){
                    reject(err);
                }
                else {
                    this._loopMember = foundMember;
                    this.log.info('grabbing user data for ID', foundMember.id);
                    resolve(foundMember);
                }
            });
        });
    }

    grabPhoneticName(){
        return new Promise((resolve, reject)=>{
            jibo.kb.loop.getSpokenNameById(this._memberID, (err, phoneticName)=>{
                if (err){
                    reject(err);
                }
                else {
                    this._loopMemberName = phoneticName;
                    resolve(phoneticName);
                }
            });
        });
    }

    update() {
        try {
            if(this._birthdayMim) {
                this._birthdayMim.update();
            }
        } catch(err) {
            this.log.error(err);
        }
    }

    destroy(timedOut, callback) {
        jibo.timer.removeListener('update', this._updateMethod);
        this._loopMemberIsSpeaker = false;
        if(this._birthdayMim) {
            this._birthdayMim.stop()
            .then(()=>{
                this._birthdayMim.destroy();
                this._birthdayMim = null;
                if (callback){
                    callback();
                }
            });
        } else if (callback){
            callback();
        }
    }
}

JiboBirthday.BIRTHDAY_TODAY_MIM = BIRTHDAY_TODAY_MIM;
JiboBirthday.BIRTHDAY_TOMORROW_MIM = BIRTHDAY_TOMORROW_MIM;
JiboBirthday.BIRTHDAY_2TO6_MIM = BIRTHDAY_2TO6_MIM;
JiboBirthday.BIRTHDAY_7TO13_MIM = BIRTHDAY_7TO13_MIM;
JiboBirthday.BIRTHDAY_LATER_MIM = BIRTHDAY_LATER_MIM;
JiboBirthday.BIRTHDAY_UNKNOWN_MIM = BIRTHDAY_UNKNOWN_MIM;
JiboBirthday.BIRTHDAY_ID_UNKNOWN_MIM = BIRTHDAY_ID_UNKNOWN_MIM;

export default JiboBirthday;
