import SubSkill from './SubSkill';
import * as BeFramework from '@be/be-framework';
import Utils from './Utils';
import Contexts from './Contexts';

let TweenManager = jibo.rendering.tween.TweenManager;
let Mim = jibo.bt.behaviors.Mim;
let ActionData = jibo.rendering.gui.actions.ActionData;

// let radiansToDegreesConversionConst = (180.0 / Math.PI);
// function radiansToDegrees(radians)
// {
// 	return (radiansToDegreesConversionConst) * radians;
// }

let degreesToRadiansConversionConst = (Math.PI / 180.0);
function degreesToRadians(degrees)
{
	return (degreesToRadiansConversionConst) * degrees;
}

const singleHourRotationSlice = (360.0 / 12.0);
const singleMinuteRotationSlice = (360.0/60.0);
const singleSecondRotationStep = degreesToRadians(singleMinuteRotationSlice);

// when animating in / out, this is the degree angle that the hands will start animating from / to when playing the animation
// the timing for the hands is dictated by the animation file by looking at the start / stop labels
const animateRotationDegree = 120;
const animateRotationRadians = degreesToRadians(animateRotationDegree);
const inEaseMethod = "cubicOut";
const outEaseMethod = "cubicIn";

const LOAD_CLOCK_VIEW_ERROR = "clock changeview error";

class JiboClock extends SubSkill {
  	constructor(clockSkill, assetPack, context=null) {
    	super();
		JiboClock.LOAD_CLOCK_VIEW_ERROR = LOAD_CLOCK_VIEW_ERROR;
		this.log = clockSkill.log.createChild('Time');

		this._clockSkill = clockSkill;
		this._assetPack = assetPack;
		this._context = context;
		this._location = null;

		this._secondHand = null;
		this._minuteHand = null;
		this._hourHand = null;

		this._clockMovieClip = null;
		this._updateMethod = this.update.bind(this);

		this._clockView = null;
		this._timeLocalMim = null;
		this._tickHands = false;
		this._swipeDown = false;
  	}

	get name() {
		return "JiboClock";
	}

	hasTimedOut(startTime) {
	    if (this._timeLocalMim) {
			const mimStatus = this._timeLocalMim.update();
			// Timeout should last at least 3 seconds, but not cut off a longer mim
			return mimStatus !== jibo.bt.Status.IN_PROGRESS && Date.now() - startTime >= 3000;
		} else {
			return Date.now() - startTime >= 3000;
		}
	}

	get movieClip() {
		return this._clockMovieClip;
	}

	init(city, state, country, callback) {
		this._location = BeFramework.utils.Location.create(city, state, country);
		this._location.needsTimezone = true;
		this._location.fetch((err)=>{
			if(err) {
				this._location = BeFramework.utils.Location.jiboHome;
				this._location.needsTimezone = true;
				this._location.fetch((err)=>{
					callback(err);
				});
			} else {
				let analyticsOtherTimezone = this._location.timezone.id !== BeFramework.utils.Location.jiboHome.timezone.id;
				this._clockSkill.analytics.currentTime(analyticsOtherTimezone);
				callback();
			}
		});
	}

	run() {
		return new Promise((resolve, reject)=>{
			try {
				let loadedError = null;
				let onCompleteCallback = (/*clockView*/)=>{
					if(loadedError) {
						reject(loadedError);
					} else {
						resolve();
					}
				};

				let onLoadedCallback = (clockView)=>{
					try {
						this.createClockGuiComponents(clockView);
						let runUpdate = ()=>{
							jibo.timer.on('update', this._updateMethod);
						};
						if(this._context === Contexts.Menu) {
							// if we're coming from the menu, we want to animate to the clock's menu_trans label before opening
							PIXI.animate.Animator.play(this._clockMovieClip, "menu_trans", ()=>{
								let currentTime = new BeFramework.utils.DateTime(null, null, this._location.timezone);
								currentTime.utc += jibo.rendering.gui.ViewManager.TRANS_TIME;
								let localTime = currentTime.getLocalTime();
								if (this._hourHand && this._minuteHand && this._secondHand) {
									this._hourHand.rotation = this.getHourRotation(localTime);
									this._minuteHand.rotation = this.getMinuteRotation(localTime);
									this._secondHand.rotation = this.getSecondRotation(localTime);
								}
								this._tickHands = true;
								runUpdate();
							});
						} else {
							// Start playing MIM immediately
							runUpdate();
							this.animateIn(this._clockMovieClip, ()=>{});
						}
					} catch(err) {
						loadedError = err;
						this.log.error(loadedError);
					}
				};

				let onFailureCallback = ()=>{
					reject(LOAD_CLOCK_VIEW_ERROR);
				};

				let changeViewOptions = {
					addView: "resources/views/clock.json",
					transitionOpen: jibo.face.views.IN,
					transitionClose: jibo.face.views.OUT
				};
				// if we've come from the menu, kill the menu view
				if(this._context === Contexts.Menu) {
					changeViewOptions.remove = true;
					changeViewOptions.transitionOpen = jibo.face.views.UP;
					changeViewOptions.transitionClose = jibo.face.views.UP;
				}
				jibo.face.views.changeView(changeViewOptions, onCompleteCallback, onFailureCallback, onLoadedCallback);
			} catch(err) {
				reject(err);
			}
		});
	}

	createClockGuiComponents(clockView) {
		this._clockView = clockView;
		this._clockView.swipeDownActions = [ new ActionData(ActionData.CALLBACK, {callback: ()=>{
			this._swipeDown = true;
			if(this._context === Contexts.Menu) {
				this._clockSkill.refresh({ nlu: {entities:{domain: this._clockSkill._clockDomain}, intent: this._clockSkill._menuIntent}, context: Contexts.Clock });
			} else {
				this._clockSkill.exit();
			}
		}})];

		this._clockMovieClip = clockView.getComponentById("clockClip").movieClip;
		this._secondHand = this._clockMovieClip.secondHand;
		this._minuteHand = this._clockMovieClip.minuteHand;
		this._hourHand = this._clockMovieClip.hourHand;
	}

	animateIn(clockMovieClip, callback) {
		this.log.debug('animate in');
		let hourPromise = this.generateClockHandAnimationInPromise(clockMovieClip, this._hourHand, this.getHourRotation, "hour");
		let minutePromise = this.generateClockHandAnimationInPromise(clockMovieClip, this._minuteHand, this.getMinuteRotation, "minute");
		let secondPromise = this.generateClockHandAnimationInPromise(clockMovieClip, this._secondHand, this.getSecondRotation, "second");

		jibo.sound.play('sfxClockIn');
		let clockPromise = new Promise((resolve, reject) => {
			try {
				PIXI.animate.Animator.play(clockMovieClip, "clock_in", ()=>{
					resolve();
				});
			} catch(err){
				reject(err);
			}
		});

		// after we finish our open animation, play the update loop to tick the clock hands
		Promise.all([clockPromise, hourPromise, minutePromise, secondPromise]).then(() => {
			this._tickHands = true;
			callback();
		});
	}

	// set up a promise that fires its resolve method when the clock hand animation is complete
	generateClockHandAnimationInPromise(clockMovieClip, handPIXIObject, getRotationCallback, handAnimationStartLabel) {
		let handsInAnimationDuration = this.getAnimationDurationMS(clockMovieClip.labels, handAnimationStartLabel, "clock_in_stop", clockMovieClip.framerate);

		let tweenOptions = { to: { alpha: 1 },
							from: { alpha: 0 },
							delay: 0,
							ease: inEaseMethod,
							duration: handsInAnimationDuration };

		return new Promise((resolve, reject) => {
				try {
					let currentTime = new BeFramework.utils.DateTime(null, null, this._location.timezone);
					currentTime.utc += tweenOptions.duration;
					let animationDoneTime = currentTime.getLocalTime();

					let animationStartPosition = Utils.findLabelFramePositionFromName(clockMovieClip.labels, handAnimationStartLabel);
					clockMovieClip.addAction(() => {
						try {
							this.animateHandIn(tweenOptions, animationDoneTime, handPIXIObject, getRotationCallback, resolve);
						}	catch(err) {
							reject(err);
						}
					}, animationStartPosition);
				} catch(err) {
					reject(err);
				}
		});
	}

	// animate a clock hand with the TweenManager
	animateHandIn(tweenOptions, animationDoneTime, handPIXIObject, rotationCallback, animationDoneCallback) {
		// rotate to the position of where the time will be after the animation has played
		tweenOptions.to.rotation = rotationCallback(animationDoneTime);
		tweenOptions.from.rotation = tweenOptions.to.rotation - animateRotationRadians;

		TweenManager.play(handPIXIObject, tweenOptions, () => {
			animationDoneCallback();
		});
	}

	animateOut(timedOut, clockMovieClip, animationFinished) {
		if((!timedOut && this._swipeDown && this._context === Contexts.Menu) || !this._clockView) {
			animationFinished();
		}
		else {
			// stop playing the tick animation
			jibo.timer.removeListener('update', this._updateMethod);

			this._secondHand = clockMovieClip.secondHand;
			this._minuteHand = clockMovieClip.minuteHand;
			this._hourHand = clockMovieClip.hourHand;

			let hourPromise = this.generateClockHandAnimationOutPromise(clockMovieClip, this._hourHand, this.getHourRotation, "clock_out");
			let minutePromise = this.generateClockHandAnimationOutPromise(clockMovieClip, this._minuteHand, this.getMinuteRotation, "clock_out");
			let secondPromise = this.generateClockHandAnimationOutPromise(clockMovieClip, this._secondHand, this.getSecondRotation, "clock_out");

			// play the clock in animation and stop the animation when it's done
			let clockPromise = new Promise((resolve, reject) => {
				try {
					this._clockView.lockInput(true);
					PIXI.animate.Animator.play(clockMovieClip, "clock_out", ()=>{
						resolve();
					});
				} catch(err){
					reject(err);
				}
			});

			// after we finish our close animation, trigger the animation done callback
			jibo.sound.play('sfxClockOut');
			Promise.all([clockPromise, hourPromise, minutePromise, secondPromise]).then(() => {
				animationFinished();
			});
		}
	}

	generateClockHandAnimationOutPromise(clockMovieClip, handPIXIObject, getRotationCallback, handAnimationStartLabel) {
		let handsOutAnimationDuration = this.getAnimationDurationMS(clockMovieClip.labels, "hands_out", "hands_out_stop", clockMovieClip.framerate);

		let tweenOptions = { to: { alpha: 0 },
							from: { alpha: handPIXIObject.alpha },
							delay: 0,
							ease: outEaseMethod,
							duration: handsOutAnimationDuration };

		return new Promise((resolve, reject) => {
				try {
					let currentTime = new BeFramework.utils.DateTime(null, null, this._location.timezone);
					currentTime.utc += tweenOptions.duration;
					let animationDoneTime = currentTime.getLocalTime();

					let animationStartPosition = Utils.findLabelFramePositionFromName(clockMovieClip.labels, handAnimationStartLabel);
					clockMovieClip.addAction(() => {
						try {
							this.animateHandOut(tweenOptions, animationDoneTime, handPIXIObject, getRotationCallback, resolve);
						} catch(err) {
							reject(err);
						}
					}, animationStartPosition);
				} catch(err) {
					reject(err);
				}
		});
	}

	getAnimationDurationMS(labelCollection, startFrameLabel, endFrameLabel, framerate) {
		let startFrameNumber = Utils.findLabelFramePositionFromName(labelCollection, startFrameLabel);
		let endFrameNumber = Utils.findLabelFramePositionFromName(labelCollection, endFrameLabel);
		// multiply by 1000 because the framerate should be in seconds and we want this to return out in MS
		return ((endFrameNumber - startFrameNumber) / framerate) * 1000;
	}

	// animate a clock hand with the TweenManager
	animateHandOut(tweenOptions, animationDoneTime, handPIXIObject, rotationCallback, animationDoneCallback) {
		// rotate to the position of where the time will be after the animation has played
		tweenOptions.from.rotation = rotationCallback(animationDoneTime);
		tweenOptions.to.rotation = tweenOptions.from.rotation + animateRotationRadians;

		TweenManager.play(handPIXIObject, tweenOptions, () => {
			animationDoneCallback();
		});
	}

	update(/*elapsedTime*/) {
		try {
			let currentTime = new BeFramework.utils.DateTime(null, null, this._location.timezone);
			if(!this._timeLocalMim) {
				this._timeLocalMim = new Mim({
					mimPath: "mims/TimeLocal.mim",
					assetPack: this._assetPack,
					getPromptData: ()=>{
						return{
							time: currentTime,
							// this returns jibo's home when not specifing a city / state / country
							where: this._location
						};
					}
				});
				this._timeLocalMim.start();
			}
			this._timeLocalMim.update();

			// wait until animationIn is finished to start ticking
			if (this._tickHands && this._hourHand && this._minuteHand && this._secondHand) {
				let localTime = currentTime.getLocalTime();
				this._hourHand.rotation = this.getHourRotation(localTime);
				this._minuteHand.rotation = this.getMinuteRotation(localTime);

				let newSecondRotation = this.getSecondRotation(localTime);

				// only play a tick sound if we're updating the rotation
				if(this._secondHand.rotation !== newSecondRotation) {
					this._tickSFXCount = this._tickSFXCount || 0;
					let tickSFX = (++this._tickSFXCount) % 2? 'sfxClockTick' : 'sfxClockTock';
					jibo.sound.play(tickSFX);
				}

				this._secondHand.rotation = newSecondRotation;
			}


		} catch(err) {
			this.log.error(err);
		}
	}

	// get the hour hand rotation in radians for a given time
	getHourRotation(time) {
		let currentHour = time.hour;
		currentHour = time.hour <= 12 ? time.hour : time.hour - 12;
		let currentMinute = time.minute;
		let minuteScale = 0.0;
		if(currentMinute !== 60.0) {
			minuteScale = (currentMinute / 60.0);
		}
		let startHourRotation = parseInt(singleHourRotationSlice * currentHour) + (singleHourRotationSlice * minuteScale);
		return degreesToRadians(startHourRotation);
	}

	// get the minute hand rotation in radians for a given time
	getMinuteRotation(time) {
		let currentMinute = time.minute;
		let currentSecond = time.seconds;

		let secondScale = 0.0;
		if(currentSecond !== 60.0) {
			secondScale = (currentSecond / 60.0);
		}
		let startMinuteRotation = parseInt(singleMinuteRotationSlice * currentMinute) + (singleMinuteRotationSlice * secondScale);
		return degreesToRadians(startMinuteRotation);
	}

	// get the second hand rotation in radians for a given time
	getSecondRotation(time) {
		let currentSecond = time.seconds;
		return singleSecondRotationStep * currentSecond;
	}

	destroy(timedOut, callback) {
		jibo.timer.removeListener('update', this._updateMethod);
		this._tickHands = false;
		this._clockView = null;
		if(this._hourHand) {
			TweenManager.stop(this._hourHand);
		}
		if(this._minuteHand) {
			TweenManager.stop(this._minuteHand);
		}
		if(this._secondHand) {
			TweenManager.stop(this._secondHand);
		}
		this._hourHand = null;
		this._minuteHand = null;
		this._secondHand = null;

		Promise.resolve()
		.then(()=>{
			return new Promise((resolve)=>{
				if(this._timeLocalMim) {
					this._timeLocalMim.stop().then(()=>{
						this._timeLocalMim.destroy();
						this._timeLocalMim = null;
						resolve();
					});
				} else {
					resolve();
				}
			});
		})
		.then(()=>{
			let viewOptions = {
				removeAll: true,
				leaveEmpty: true,
				transitionOpen: jibo.face.views.IN,
				transitionClose: this._context !== Contexts.Menu || timedOut || !this._swipeDown ? jibo.face.views.OUT : jibo.face.views.DOWN
			};
			let onFailure = (err) => {
				this.log.warn('View close failure:', err);
				callback();
			}
			this._swipeDown = false;
			jibo.face.views.changeView(viewOptions, callback, onFailure);
		});
	}
}

export default JiboClock;
